INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 1, 'What is AI?', 'Understanding Artificial Intelligence', 'This class introduces the fundamental concept of artificial intelligence and how it already touches your everyday life. You''ll learn what AI actually is, how it differs from regular software, and why everyone is talking about it.', '[{"title":"What AI Actually Means","content":"We break down the term artificial intelligence into plain English. You''ll understand the difference between AI in movies and AI in real life."},{"title":"AI You Already Use","content":"Discover the AI tools you interact with daily without even realizing it. From autocorrect to photo tagging, AI is already part of your routine."},{"title":"How AI Learns","content":"A simple explanation of how computers can learn from examples instead of following rigid instructions. We''ll use the analogy of teaching a child to recognize animals."},{"title":"Why AI Matters Now","content":"Understand why AI has exploded in popularity in recent years. We''ll cover what changed technologically and why it affects everyone."}]', '["Define artificial intelligence in your own words","Identify at least five AI tools you already use daily","Explain the basic concept of how machines learn from data"]', '[{"title":"AI Scavenger Hunt","description":"Open your phone and identify at least five features or apps that use AI. Write down what each one does and how you think AI helps it work.","type":"hands-on"},{"title":"AI vs. Not AI","description":"Look at a list of ten technologies and decide which ones use AI and which ones don''t. Discuss your reasoning with the class.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about what artificial intelligence is. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 2, 'Smart Assistants 101', 'Siri, Alexa & Google Assistant', 'This class covers how voice-powered smart assistants work and what they can do for you. You''ll get hands-on practice using smart assistants for everyday tasks like setting reminders, checking the weather, and answering questions.', '[{"title":"Meet Your Smart Assistants","content":"An introduction to the most popular smart assistants including Siri, Alexa, and Google Assistant. Learn which devices they live on and how to activate them."},{"title":"How Voice Assistants Understand You","content":"Discover how these assistants turn your spoken words into actions. We''ll explain speech recognition and natural language processing in simple terms."},{"title":"Everyday Tasks Made Easy","content":"Learn the most useful commands and questions you can ask your smart assistant. From timers to trivia, you''ll build confidence talking to your device."},{"title":"Tips, Tricks & Limitations","content":"Understand what smart assistants do well and where they fall short. We''ll also cover privacy basics so you know what your assistant is listening to."}]', '["Set up and activate a smart assistant on your phone or device","Use voice commands to complete at least five practical everyday tasks","Understand the basic privacy settings for your smart assistant"]', '[{"title":"Assistant Challenge","description":"Complete a list of ten tasks using only your voice assistant, such as setting a timer, sending a text, playing a song, and getting directions. Check off each one as you go.","type":"hands-on"},{"title":"Compare and Contrast","description":"Ask the same five questions to two different smart assistants and compare the answers. Note which one gave better, faster, or more helpful responses.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about smart assistants like Siri, Alexa, and Google Assistant. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 3, 'AI in Your Phone', 'How AI Powers Your Device', 'This class reveals the hidden AI features built into your smartphone that make it smarter every day. You''ll explore camera enhancements, battery optimization, predictive text, and other AI-driven features you''re already using.', '[{"title":"Your Phone''s Hidden Brain","content":"Modern smartphones have dedicated AI chips that power features behind the scenes. Learn what these chips do and why phone makers invest heavily in AI."},{"title":"Camera AI Magic","content":"Discover how your phone''s camera uses AI to improve photos automatically. From night mode to portrait blur, AI is doing the heavy lifting."},{"title":"Predictive Features","content":"Understand how your phone predicts what you''ll type next, which apps you''ll open, and even how much battery you''ll need. These are all powered by AI learning your habits."},{"title":"Personalizing Your Experience","content":"Learn how your phone adapts to your usage patterns over time. We''ll cover how AI customizes everything from brightness to app suggestions."}]', '["Identify at least five AI-powered features on your own smartphone","Use your phone''s AI camera features to take an enhanced photo","Adjust AI-related settings on your phone for a better experience"]', '[{"title":"Phone AI Tour","description":"Go through your phone''s settings and features to find every AI-powered tool. Take screenshots of at least five AI features and describe what each one does.","type":"hands-on"},{"title":"Before and After Photos","description":"Take a photo with all AI camera features turned off, then take the same photo with them turned on. Compare the results side by side and note the differences.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI powers their smartphone. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 4, 'Writing with AI', 'ChatGPT & AI Writing Tools', 'This class teaches you how to use AI writing assistants like ChatGPT to help with emails, messages, and creative writing. You''ll learn how to give clear instructions to get the best results and understand what AI writing tools can and cannot do.', '[{"title":"What Are AI Writing Tools?","content":"An overview of popular AI writing assistants including ChatGPT, Google Gemini, and others. Understand what these tools are and how they generate text."},{"title":"Talking to AI: The Art of Prompts","content":"Learn how to write clear prompts that get useful results. We''ll practice turning vague requests into specific instructions that AI can follow well."},{"title":"Practical Writing Tasks","content":"Use AI to help draft an email, summarize a long article, and brainstorm ideas. You''ll see how AI can save you time on everyday writing tasks."},{"title":"Knowing the Limits","content":"Understand when AI writing is helpful and when you should rely on your own judgment. We''ll discuss accuracy, tone, and the importance of reviewing AI output."}]', '["Write effective prompts that produce useful AI-generated text","Use an AI writing tool to draft an email and a short summary","Identify common mistakes and limitations in AI-generated writing"]', '[{"title":"Prompt Practice","description":"Write three different prompts asking an AI tool to draft the same email. Compare the outputs and identify which prompt gave the best result and why.","type":"hands-on"},{"title":"AI Editing Partner","description":"Write a short paragraph about your favorite hobby, then ask an AI writing tool to improve it. Compare both versions and decide which parts of the AI''s suggestions you''d keep.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI writing tools like ChatGPT. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 5, 'AI Photo Magic', 'Edit & Enhance with AI', 'This class shows you how AI-powered photo tools can transform your pictures with just a few taps. You''ll learn to remove backgrounds, enhance blurry images, apply smart edits, and create fun effects using free AI tools.', '[{"title":"How AI Sees Photos","content":"Understand the basics of how AI can recognize objects, faces, and scenes in your photos. This is the foundation that makes all AI photo editing possible."},{"title":"One-Tap Enhancements","content":"Learn to use AI tools that automatically improve brightness, color, and sharpness. We''ll try free apps that make your photos look professional in seconds."},{"title":"Removing and Replacing","content":"Discover how AI can remove unwanted objects from photos or even change backgrounds. We''ll practice with popular free tools that make this easy."},{"title":"Fun with AI Filters","content":"Explore creative AI features like style transfer, aging filters, and artistic effects. Understand how these fun tools work and what happens to your photos behind the scenes."}]', '["Use an AI tool to automatically enhance the quality of a photo","Remove an unwanted object or background from a photo using AI","Apply at least two creative AI effects to your own photos"]', '[{"title":"Photo Makeover","description":"Choose three of your own photos and use a free AI editing app to enhance each one. Save before and after versions and share your favorite transformation.","type":"hands-on"},{"title":"Background Swap","description":"Use an AI background removal tool to remove the background from a selfie, then place yourself in a fun new setting. Try at least two different backgrounds.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI photo editing and enhancement tools. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 6, 'Smart Home Basics', 'AI-Powered Automation', 'This class introduces you to smart home technology and how AI makes your home more convenient, comfortable, and efficient. You''ll learn about smart devices, how they connect, and how to set up simple automations.', '[{"title":"What Is a Smart Home?","content":"Learn what makes a home smart and how AI ties everything together. We''ll cover the most popular smart home devices and what they do."},{"title":"Getting Connected","content":"Understand how smart devices talk to each other through Wi-Fi, Bluetooth, and smart hubs. We''ll explain the basics of setting up your first smart device."},{"title":"Simple Automations","content":"Discover how to create routines that make things happen automatically, like turning lights on at sunset. We''ll walk through setting up your first automation step by step."},{"title":"Choosing the Right Devices","content":"Learn which smart home devices offer the best value for beginners. We''ll discuss budget-friendly options and what to look for when shopping."}]', '["Explain how smart home devices use AI to automate daily tasks","Set up a simple smart home routine or automation","Choose appropriate smart home devices based on your needs and budget"]', '[{"title":"Design Your Smart Home","description":"Draw a floor plan of your home and mark where you would place smart devices. List what each device would do and what automations you would set up.","type":"hands-on"},{"title":"Build a Morning Routine","description":"Using a smart assistant app, create a morning routine automation that includes at least three actions such as turning on lights, reading the weather, and starting music.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about smart home technology and AI-powered automation. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 7, 'AI in Entertainment', 'How Streaming Uses AI', 'This class explains how AI powers the entertainment you enjoy every day, from Netflix recommendations to Spotify playlists. You''ll understand how algorithms learn your taste and how to take control of your recommendations.', '[{"title":"How Recommendations Work","content":"Learn how streaming services like Netflix and Spotify figure out what you''ll like. We''ll explain the recommendation engine in plain language using relatable examples."},{"title":"The Algorithm Behind Your Feed","content":"Understand what an algorithm is and how it tracks what you watch, listen to, and skip. You''ll see how small actions influence what content gets suggested."},{"title":"AI in Gaming and Video","content":"Discover how AI creates smarter video game opponents and generates content in gaming. We''ll also explore how AI helps with video editing and special effects."},{"title":"Taking Control of Your Feed","content":"Learn practical tips for training your recommendations to show you better content. We''ll cover how to reset suggestions and use features like thumbs up and thumbs down effectively."}]', '["Explain how streaming recommendation algorithms learn your preferences","Identify three ways AI enhances your entertainment experience","Use rating and feedback features to improve your streaming recommendations"]', '[{"title":"Recommendation Experiment","description":"Rate ten items on a streaming service you use and then check how your recommendations change over the next day. Write down what you noticed before and after.","type":"hands-on"},{"title":"Algorithm Detective","description":"Open three different entertainment apps and find where each one uses AI to suggest content. Take screenshots and explain how you think each recommendation was generated.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI powers entertainment and streaming services. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 8, 'AI Shopping Assistant', 'Personalized Recommendations', 'This class reveals how online stores use AI to show you products you''re likely to buy and personalize your shopping experience. You''ll learn to use AI-powered tools to find better deals, compare products, and shop smarter.', '[{"title":"How Stores Know What You Want","content":"Discover how Amazon, Target, and other retailers use AI to track your browsing and suggest products. We''ll explain how your shopping history shapes what you see."},{"title":"Price Tracking and Deal Finding","content":"Learn about AI tools and browser extensions that automatically find coupons and track price drops. We''ll set up a free tool that saves you money."},{"title":"AI Product Reviews and Comparisons","content":"Explore how AI can summarize hundreds of product reviews into quick insights. We''ll practice using AI to compare products before buying."},{"title":"Smart Shopping Tips","content":"Learn to recognize when AI recommendations are helpful versus when they''re just trying to get you to spend more. We''ll cover practical strategies for staying in control."}]', '["Explain how online retailers use AI to personalize your shopping experience","Use an AI-powered tool to find deals or compare products","Recognize the difference between helpful recommendations and manipulative marketing"]', '[{"title":"Deal Finder Setup","description":"Install a free AI-powered browser extension like Honey or CamelCamelCamel. Search for a product you''ve been wanting and see what deals or price history the tool reveals.","type":"hands-on"},{"title":"AI Review Summary","description":"Find a product with hundreds of reviews on Amazon. Use an AI tool to summarize the key pros and cons, then compare that summary with your own reading of the top reviews.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI powers online shopping and product recommendations. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 9, 'AI in Social Media', 'Algorithms & Curation', 'This class explains how social media platforms use AI to decide what you see in your feed and what goes viral. You''ll learn how algorithms curate your experience and how to take more control over your social media consumption.', '[{"title":"What Is a Social Media Algorithm?","content":"Understand what algorithms are and how platforms like Instagram, TikTok, and Facebook use them. We''ll explain why two people following the same accounts see different feeds."},{"title":"How AI Decides What You See","content":"Learn the signals AI uses to rank content in your feed, including likes, watch time, and shares. We''ll break down how a single scroll teaches the algorithm about you."},{"title":"Filter Bubbles and Echo Chambers","content":"Discover how AI curation can limit the variety of viewpoints you encounter. We''ll discuss how to recognize when you''re in a filter bubble and what to do about it."},{"title":"Taking Back Your Feed","content":"Learn practical steps to influence what your social media shows you. We''ll cover muting, blocking, interest settings, and how to reset your algorithm."}]', '["Explain how social media algorithms decide which posts appear in your feed","Identify at least three signals that algorithms use to rank content","Adjust your social media settings to have more control over what you see"]', '[{"title":"Algorithm Audit","description":"Spend ten minutes scrolling your favorite social media app. Write down what types of content appear most often and guess why the algorithm is showing you each post.","type":"hands-on"},{"title":"Feed Reset Experiment","description":"Use your platform''s settings to clear your interest data or tell it to show less of a certain topic. Compare your feed before and after and note any changes.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI and algorithms shape social media feeds. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 10, 'Voice & Speech AI', 'How Voice Recognition Works', 'This class explores how AI can understand human speech and convert it into text or actions. You''ll learn how voice recognition technology has evolved, how it works under the hood, and how to get the best results from voice tools.', '[{"title":"From Sound to Words","content":"Learn the basic process of how AI converts your voice into text. We''ll explain how sound waves become words your device can understand."},{"title":"How AI Handles Accents and Noise","content":"Discover how modern voice AI deals with different accents, background noise, and unclear speech. We''ll discuss why it sometimes gets things wrong and how it''s improving."},{"title":"Dictation and Transcription Tools","content":"Explore free tools that let you dictate messages, transcribe meetings, and create notes with your voice. We''ll practice using built-in dictation features on your device."},{"title":"The Future of Voice AI","content":"Learn about emerging voice technologies like real-time translation and voice cloning. We''ll discuss the exciting possibilities and potential concerns."}]', '["Explain the basic process of how voice recognition AI converts speech to text","Use dictation tools on your device to compose a message hands-free","Identify situations where voice AI tools can save you time in daily life"]', '[{"title":"Dictation Challenge","description":"Use your phone''s voice dictation feature to compose a full email without touching the keyboard. Try including punctuation and see how accurately the AI transcribes your words.","type":"hands-on"},{"title":"Accent and Clarity Test","description":"Speak the same sentence to your voice assistant at different speeds, volumes, and with different emphasis. Record how accurately it understands each version and note what works best.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about voice recognition and speech AI technology. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 11, 'AI Translation Tools', 'Breaking Language Barriers', 'This class covers AI-powered translation tools that let you communicate across languages instantly. You''ll learn how to use tools like Google Translate and others for text, voice, and even camera-based translation in real time.', '[{"title":"How AI Translation Works","content":"Understand the basics of how AI translates between languages without memorizing a dictionary. We''ll explain how machine learning lets AI grasp context and meaning."},{"title":"Text and Voice Translation","content":"Learn to use popular translation apps for both typed and spoken conversations. We''ll practice having a basic conversation translated in real time."},{"title":"Camera and Image Translation","content":"Discover how to point your phone camera at signs, menus, or documents in another language and get instant translations. We''ll try this feature hands-on."},{"title":"Tips for Better Translations","content":"Learn how to phrase your words to get more accurate translations from AI tools. We''ll cover common pitfalls and tricks for getting reliable results."}]', '["Use an AI translation tool to translate text, voice, and images in real time","Explain the basics of how AI translation differs from word-by-word lookup","Apply practical tips to get more accurate translations from AI tools"]', '[{"title":"Camera Translation Walk","description":"Use Google Translate''s camera feature to translate printed text from at least three different sources, such as a food label, a book title, or a website in another language.","type":"hands-on"},{"title":"Conversation Translator","description":"Pair up with someone and use a translation app''s conversation mode to have a short chat in two different languages. Note where the translation was accurate and where it struggled.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI-powered translation tools and how they break language barriers. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 12, 'AI Health & Fitness', 'Wearables & Tracking', 'This class explores how AI in fitness trackers and health apps helps you monitor your well-being and reach your goals. You''ll learn how wearable devices use AI to track steps, sleep, heart rate, and more.', '[{"title":"How Wearables Use AI","content":"Learn how devices like Fitbit, Apple Watch, and others use AI to interpret your body''s data. We''ll explain how sensors and algorithms work together to track your health."},{"title":"Understanding Your Health Data","content":"Discover what your health data actually means and how AI turns raw numbers into useful insights. We''ll cover metrics like resting heart rate, sleep stages, and activity zones."},{"title":"AI Fitness Coaching","content":"Explore apps that use AI to create personalized workout plans and nutrition suggestions. We''ll look at free options that adapt to your fitness level and goals."},{"title":"Privacy and Your Health Data","content":"Understand who has access to your health data and how to protect it. We''ll cover the privacy settings you should check on your fitness apps and devices."}]', '["Explain how AI in wearable devices tracks and interprets health data","Read and understand key health metrics from a fitness tracker or app","Adjust privacy settings on a health or fitness app to protect your data"]', '[{"title":"Health Dashboard Review","description":"Open your fitness tracker app or phone''s built-in health app. Explore the dashboard and write down five things the AI is tracking about you and what insights it provides.","type":"hands-on"},{"title":"AI Workout Plan","description":"Try a free AI fitness app and let it generate a personalized workout based on your goals and fitness level. Complete the suggested workout and rate how well the AI tailored it to you.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI in health tracking and fitness wearables. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 13, 'AI in Navigation', 'GPS & Maps with AI', 'This class explains how AI makes your maps and navigation apps smarter than ever, predicting traffic and finding the fastest routes. You''ll learn how apps like Google Maps and Waze use AI and how to get the most out of these tools.', '[{"title":"How AI Powers Your Maps","content":"Learn how navigation apps combine GPS data with AI to give you accurate directions. We''ll explain how millions of phones contribute data that makes maps smarter."},{"title":"Predicting Traffic","content":"Discover how AI predicts traffic jams before they happen by analyzing patterns and real-time data. We''ll look at how this saves you time on your daily commute."},{"title":"Beyond Basic Directions","content":"Explore advanced features like finding parking, estimating arrival times, and discovering nearby places. We''ll practice using AI-powered map features you might not know about."},{"title":"Offline Maps and Accessibility","content":"Learn how to use maps without an internet connection and explore accessibility features powered by AI. We''ll set up offline maps for areas you visit frequently."}]', '["Explain how AI in navigation apps predicts traffic and optimizes routes","Use advanced AI features in your maps app beyond basic turn-by-turn directions","Download and use offline maps for situations without internet access"]', '[{"title":"Route Comparison","description":"Plan a trip to the same destination using two different navigation apps. Compare the routes, estimated times, and traffic predictions each AI provides and note the differences.","type":"hands-on"},{"title":"Hidden Features Hunt","description":"Explore your favorite maps app and find at least three AI-powered features you haven''t used before, such as parking difficulty indicators, popular times at businesses, or fuel-efficient routes.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI powers navigation and maps applications. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 14, 'Email & AI', 'Smart Compose & Filtering', 'This class shows you how AI makes email faster and safer by writing suggestions, sorting your inbox, and blocking spam. You''ll learn to use AI email features to save time and keep your inbox organized.', '[{"title":"How AI Sorts Your Inbox","content":"Learn how email services like Gmail use AI to automatically sort messages into categories like Primary, Social, and Promotions. We''ll explain how AI decides where each email goes."},{"title":"Smart Compose and Quick Replies","content":"Discover how AI suggests what you should type next when writing emails. We''ll practice using smart compose and quick reply features to write emails faster."},{"title":"Spam and Phishing Detection","content":"Understand how AI protects you from dangerous emails by spotting spam and phishing attempts. We''ll learn what to look for when AI flags something suspicious."},{"title":"AI Email Productivity Tips","content":"Explore additional AI features like email scheduling, follow-up reminders, and search intelligence. We''ll set up features that keep your inbox under control."}]', '["Use smart compose and quick reply features to write emails more efficiently","Explain how AI filters spam and detects phishing attempts in your inbox","Set up AI-powered email organization features to manage your inbox better"]', '[{"title":"Smart Compose Speed Test","description":"Write two versions of the same email, one using smart compose suggestions and one typing everything manually. Compare how long each takes and how natural the AI-assisted version sounds.","type":"hands-on"},{"title":"Inbox Organization","description":"Review your email settings and enable AI-powered sorting and filtering features. Move at least ten emails into the correct categories and set up one new filter or rule.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about how AI powers email features like smart compose, spam filtering, and inbox organization. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 15, 'AI Safety Online', 'Deepfakes & Misinformation', 'This class teaches you how to spot AI-generated fake content including deepfake videos, fake images, and misleading articles. You''ll develop critical thinking skills to navigate the internet safely in an age of AI-generated content.', '[{"title":"What Are Deepfakes?","content":"Learn what deepfake technology is and how AI can create realistic fake videos and images. We''ll look at examples so you know what to watch for."},{"title":"Spotting AI-Generated Content","content":"Discover practical techniques for identifying AI-generated text, images, and videos. We''ll practice looking for telltale signs that something was made by AI."},{"title":"Misinformation and AI","content":"Understand how AI can be used to spread false information at scale. We''ll discuss real-world examples and how misinformation campaigns work."},{"title":"Protecting Yourself","content":"Learn concrete steps to verify information before believing or sharing it. We''ll build a personal checklist for evaluating content you encounter online."}]', '["Identify common signs that an image, video, or article was generated by AI","Use fact-checking tools and techniques to verify suspicious online content","Explain why AI-generated misinformation is a growing concern and how to combat it"]', '[{"title":"Deepfake Detective","description":"Look at a set of images and short videos and try to determine which ones are AI-generated and which are real. Write down the clues that helped you decide.","type":"hands-on"},{"title":"Fact-Check Challenge","description":"Find a viral social media post or news claim and use at least two fact-checking websites to verify it. Write a short summary of whether it was true, false, or misleading.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI safety, deepfakes, and online misinformation. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 16, 'AI Privacy Basics', 'Understanding Data Collection', 'This class explains how AI systems collect, store, and use your personal data to work effectively. You''ll learn what data you''re sharing, why it matters, and practical steps to protect your privacy while still using AI tools.', '[{"title":"What Data AI Collects","content":"Discover the types of personal data that AI-powered apps and services gather about you. We''ll cover everything from location data to voice recordings and browsing habits."},{"title":"Why Companies Want Your Data","content":"Understand the business model behind free AI services and why your data is valuable. We''ll explain how your information is used for advertising, training AI, and product improvement."},{"title":"Reading Privacy Settings","content":"Learn to navigate privacy settings on your phone and popular apps. We''ll walk through the most important settings to check and adjust right away."},{"title":"Practical Privacy Steps","content":"Build a simple action plan to reduce unnecessary data sharing while still enjoying AI features. We''ll cover password managers, permissions, and data deletion requests."}]', '["Identify what types of personal data AI tools collect about you","Adjust privacy settings on your phone and apps to limit unnecessary data sharing","Explain the tradeoff between AI convenience and personal data privacy"]', '[{"title":"Privacy Audit","description":"Check the privacy settings on your three most-used apps. Write down what data each app collects and adjust at least two settings on each app to improve your privacy.","type":"hands-on"},{"title":"Data Download","description":"Use Google, Apple, or Facebook''s data download feature to request a copy of what they know about you. Review the data and identify three things that surprised you.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI privacy and data collection practices. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 17, 'AI in Education', 'Learning Tools & Tutoring', 'This class explores how AI is transforming the way we learn, from personalized tutoring to language learning apps. You''ll discover AI-powered educational tools that can help you or your family learn new skills faster and more effectively.', '[{"title":"AI Tutors and Learning Apps","content":"Meet the most popular AI-powered learning tools like Khan Academy, Duolingo, and Photomath. We''ll explore how each one uses AI to personalize your learning experience."},{"title":"How AI Personalizes Learning","content":"Understand how AI adapts lessons to your skill level and learning pace. We''ll explain how these systems figure out what you know and what you need to practice more."},{"title":"AI for Kids and Students","content":"Discover age-appropriate AI learning tools for children and students. We''ll cover homework helpers, reading assistants, and math tools that make learning fun."},{"title":"Lifelong Learning with AI","content":"Explore how AI can help adults learn new skills, languages, or hobbies at any age. We''ll set up a personalized learning plan using free AI tools."}]', '["Identify at least three AI-powered educational tools and explain how they personalize learning","Use an AI tutoring or learning app to complete a short lesson","Evaluate which AI learning tools are best suited for your personal goals"]', '[{"title":"AI Tutor Test Drive","description":"Sign up for a free AI learning app like Khan Academy or Duolingo. Complete one lesson and write down three ways the AI personalized the experience for you.","type":"hands-on"},{"title":"Homework Helper","description":"Take a real question or problem you''re curious about and ask an AI tool to explain it to you step by step. Rate how well the AI taught you and what it could have done better.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI-powered educational tools and tutoring systems. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 18, 'AI Creativity', 'Art, Music & Content', 'This class dives into the exciting world of AI-generated art, music, and creative content that anyone can make. You''ll use free AI tools to create your own artwork and music, even if you have zero artistic experience.', '[{"title":"AI Art Generation","content":"Learn how AI tools like DALL-E and others create images from simple text descriptions. We''ll explore how these tools work and what makes a good art prompt."},{"title":"AI Music and Sound","content":"Discover tools that let you create music, sound effects, and beats using AI. We''ll listen to examples and try creating a short piece of AI-generated music."},{"title":"AI Video and Content Creation","content":"Explore how AI is being used to create videos, presentations, and social media content. We''ll look at accessible tools that help you produce professional-looking content."},{"title":"The Creative Debate","content":"Discuss important questions about AI creativity, including copyright, originality, and the role of human artists. We''ll form our own opinions on where AI creativity is headed."}]', '["Use an AI art tool to generate an original image from a text description","Create a short piece of AI-generated music or audio using a free tool","Discuss the ethical considerations surrounding AI-generated creative content"]', '[{"title":"AI Art Gallery","description":"Use a free AI image generator to create three different images by writing creative prompts. Experiment with different styles and descriptions to see how your words affect the output.","type":"hands-on"},{"title":"AI Music Maker","description":"Use a free AI music tool to create a short 30-second piece of music. Choose a mood and style, then listen to what the AI creates. Try generating two different genres and compare them.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about AI-powered creative tools for art, music, and content creation. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 19, 'Future of AI', 'Trends & Predictions', 'This class looks ahead at where AI technology is going and how it will shape our daily lives in the coming years. You''ll explore upcoming AI trends, career impacts, and how to stay informed as AI continues to evolve.', '[{"title":"AI Trends Right Now","content":"Explore the biggest AI developments happening today, from self-driving cars to AI doctors. We''ll separate real progress from media hype so you know what''s actually coming."},{"title":"How AI Will Change Work","content":"Understand how AI might affect different jobs and industries in the near future. We''ll discuss which skills will be most valuable and how to prepare rather than worry."},{"title":"AI and Society","content":"Consider how AI will impact healthcare, education, transportation, and the environment. We''ll look at both the exciting opportunities and the challenges we need to address."},{"title":"Staying Informed","content":"Learn how to keep up with AI developments without getting overwhelmed. We''ll set up simple ways to follow trustworthy AI news and continue learning."}]', '["Identify three major AI trends that will impact everyday life in the near future","Explain how AI may change the job market and what skills will remain valuable","Find and follow at least two reliable sources for staying informed about AI developments"]', '[{"title":"Future Predictions","description":"Write down three predictions about how AI will change your daily life in the next five years. Research each prediction online and rate how likely it is based on current technology.","type":"hands-on"},{"title":"AI News Feed Setup","description":"Find and subscribe to at least two trustworthy AI news sources, such as newsletters, YouTube channels, or podcasts. Read or watch one recent piece from each and summarize what you learned.","type":"hands-on"}]', 'You are an AI tutor helping a beginner learn about future AI trends and predictions. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 20);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('beginner', 20, 'Your AI Toolkit', 'Building Your AI Workflow', 'This class brings everything together by helping you build a personalized collection of AI tools for your daily life. You''ll create a practical AI workflow that saves you time and makes everyday tasks easier.', '[{"title":"Reviewing Your AI Journey","content":"Look back at everything you''ve learned across the beginner series and identify which tools resonated most with you. We''ll recap the key AI categories and their practical uses."},{"title":"Building Your Personal Toolkit","content":"Select the AI tools that match your lifestyle, goals, and interests. We''ll organize them into categories like productivity, creativity, health, and communication."},{"title":"Creating Daily AI Habits","content":"Design a realistic daily routine that incorporates AI tools without feeling overwhelming. We''ll map out morning, afternoon, and evening AI touchpoints that add real value."},{"title":"Next Steps in Your AI Education","content":"Plan your continued AI learning journey with resources, communities, and intermediate topics to explore. We''ll set personal goals for the next month of AI exploration."}]', '["Assemble a personalized toolkit of at least five AI tools for daily use","Create a practical daily workflow that incorporates AI to save time and effort","Set specific goals for continuing your AI education beyond this beginner course"]', '[{"title":"My AI Toolkit Card","description":"Create a one-page reference card listing your top AI tools organized by category. Include the tool name, what it does, and one tip for getting the best results from each one.","type":"hands-on"},{"title":"30-Day AI Challenge","description":"Write a personal 30-day plan for trying one new AI feature or tool each day. Include what you''ll try, which app or service you''ll use, and what you hope to learn from each experiment.","type":"hands-on"}]', 'You are an AI tutor helping a beginner build their personal AI toolkit and daily workflow. Use simple language, everyday examples, and be encouraging. Explain concepts as if talking to someone with no tech background.', 25);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 1, 'Prompt Engineering Fundamentals', 'Writing Effective Prompts', 'Learn the art and science of crafting prompts that consistently produce high-quality AI outputs. This class covers prompt structures, techniques like chain-of-thought and few-shot prompting, and strategies for iterating toward better results.', '[{"title":"Anatomy of a Great Prompt","content":"Break down the key components of effective prompts including context, instructions, constraints, and output format. Understand why specificity and structure dramatically improve AI responses."},{"title":"Prompting Techniques","content":"Explore proven techniques such as few-shot prompting, chain-of-thought reasoning, and role-based prompting. Learn when to apply each technique for maximum effectiveness."},{"title":"Iterative Prompt Refinement","content":"Master the process of analyzing AI outputs and refining your prompts through systematic iteration. Develop a feedback loop that consistently improves results over multiple rounds."},{"title":"Prompt Templates & Libraries","content":"Build reusable prompt templates for common business tasks like summarization, analysis, and content creation. Organize and maintain a personal prompt library for efficiency."},{"title":"Advanced Prompt Strategies","content":"Tackle complex multi-step tasks by breaking them into prompt chains and using system-level instructions. Handle edge cases and learn to debug prompts that produce unexpected outputs."}]', '["Construct well-structured prompts that produce consistent, high-quality AI outputs","Apply advanced prompting techniques including few-shot, chain-of-thought, and role-based approaches","Build and maintain a reusable prompt template library for common business tasks"]', '[{"title":"Prompt Makeover Challenge","description":"Take five poorly written prompts and rewrite them using the techniques learned in class, then compare the outputs side by side to measure improvement.","type":"hands-on"},{"title":"Build Your Prompt Playbook","description":"Create a personal prompt template library with at least five reusable templates covering summarization, analysis, email drafting, brainstorming, and data extraction.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master prompt engineering for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 2, 'AI for Document Processing', 'Summarize, Analyze, Extract', 'Master the use of AI tools to process large volumes of documents quickly and accurately. Learn to summarize reports, extract key data points, and analyze contracts, invoices, and other business documents at scale.', '[{"title":"Document Summarization Techniques","content":"Learn how to use AI to create executive summaries, bullet-point breakdowns, and layered summaries of lengthy documents. Understand how to control summary length, tone, and focus areas."},{"title":"Data Extraction from Documents","content":"Use AI to pull structured data from unstructured documents such as contracts, invoices, and forms. Learn to define extraction schemas and validate outputs for accuracy."},{"title":"Comparative Document Analysis","content":"Leverage AI to compare multiple documents, identify differences, and highlight key changes between versions. Apply this to contract reviews, policy updates, and competitive analysis."},{"title":"Batch Processing Workflows","content":"Set up workflows to process multiple documents in sequence or parallel using AI tools. Learn to handle different file formats and maintain consistency across large document sets."},{"title":"Quality Assurance & Validation","content":"Develop strategies for verifying AI-generated summaries and extractions against source documents. Build checklists and spot-check processes to ensure accuracy in professional settings."}]', '["Use AI to accurately summarize lengthy documents into actionable executive briefs","Extract structured data from unstructured business documents like contracts and invoices","Design batch processing workflows for handling large volumes of documents efficiently"]', '[{"title":"Contract Key Terms Extractor","description":"Upload a sample contract and use AI to extract all key terms, dates, obligations, and financial figures into a structured spreadsheet format.","type":"hands-on"},{"title":"Multi-Document Summary Report","description":"Process three related business documents and produce a single consolidated summary that highlights common themes, discrepancies, and recommended actions.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master document processing with AI for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 3, 'Automating Repetitive Tasks', 'Save Time with AI', 'Identify repetitive tasks in your daily workflow and learn how to automate them using AI-powered tools. This class teaches you to reclaim hours each week by building simple yet powerful automations for common business activities.', '[{"title":"Identifying Automation Opportunities","content":"Learn a systematic framework for auditing your daily tasks and identifying the best candidates for AI automation. Prioritize by time saved, frequency, and complexity to maximize impact."},{"title":"Text-Based Automations","content":"Automate repetitive writing tasks such as email responses, report formatting, and data entry using AI tools. Build templates and macros that handle routine text processing with minimal input."},{"title":"File & Data Automations","content":"Set up AI-driven automations for organizing files, converting formats, and processing incoming data. Learn to create triggers that automatically handle routine file management tasks."},{"title":"Communication Automations","content":"Automate meeting scheduling, follow-up emails, status updates, and notification workflows using AI assistants. Reduce the manual overhead of keeping teams informed and aligned."},{"title":"Measuring & Optimizing Automations","content":"Track time saved and error reduction from your automations to quantify their value. Learn to iterate on and improve automations as your needs evolve over time."}]', '["Identify and prioritize the highest-impact automation opportunities in your daily workflow","Build AI-powered automations for repetitive text, data, and communication tasks","Measure the time savings and efficiency gains from implemented automations"]', '[{"title":"Task Audit & Automation Plan","description":"Conduct a detailed audit of your weekly tasks, identify the top five candidates for automation, and build a working AI automation for at least one of them.","type":"hands-on"},{"title":"Email Auto-Responder Setup","description":"Create an AI-powered system that drafts contextually appropriate replies to common email types you receive, ready for your review and one-click send.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master task automation with AI for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 4, 'AI Data Analysis', 'Spreadsheets & Data Insights', 'Transform raw data into actionable business insights using AI-powered analysis tools. Learn to clean datasets, identify trends, generate visualizations, and make data-driven recommendations without needing advanced statistics knowledge.', '[{"title":"Data Cleaning with AI","content":"Use AI to identify and fix common data quality issues such as duplicates, missing values, and inconsistent formatting. Learn to prepare messy real-world datasets for reliable analysis."},{"title":"Exploratory Data Analysis","content":"Leverage AI to quickly explore datasets, generate descriptive statistics, and surface interesting patterns. Ask natural-language questions about your data and get immediate analytical answers."},{"title":"Trend Identification & Forecasting","content":"Apply AI tools to detect trends, seasonality, and anomalies in business data. Generate simple forecasts and understand their limitations for decision-making."},{"title":"Data Visualization with AI","content":"Create professional charts, dashboards, and visual reports using AI-assisted tools. Learn best practices for choosing the right visualization type to communicate your findings effectively."},{"title":"From Insights to Action","content":"Translate analytical findings into clear business recommendations and presentations. Learn to frame data stories that drive decision-making across your organization."}]', '["Clean and prepare real-world datasets for analysis using AI-powered tools","Identify meaningful trends, patterns, and anomalies in business data","Create compelling data visualizations and translate insights into actionable recommendations"]', '[{"title":"Sales Data Deep Dive","description":"Take a sample sales dataset, use AI to clean it, identify the top three trends, and produce a visual dashboard with written recommendations for leadership.","type":"hands-on"},{"title":"Anomaly Detective","description":"Analyze a provided dataset containing hidden anomalies, use AI to detect and explain them, and present your findings in a one-page executive summary.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master data analysis with AI for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 5, 'AI for Marketing', 'Content & Campaign Optimization', 'Leverage AI to supercharge your marketing efforts from content creation to campaign analysis. Learn to generate targeted copy, optimize campaigns in real time, and personalize messaging at scale across multiple channels.', '[{"title":"AI-Powered Content Creation","content":"Generate blog posts, social media content, ad copy, and email campaigns using AI tools with brand-consistent voice and messaging. Learn to maintain quality while dramatically increasing content output."},{"title":"Audience Segmentation & Personalization","content":"Use AI to analyze customer data and create detailed audience segments for targeted marketing. Build personalized messaging frameworks that speak directly to each segment''s needs and motivations."},{"title":"Campaign Optimization","content":"Apply AI analytics to monitor campaign performance and identify optimization opportunities in real time. Learn A/B testing strategies enhanced by AI-driven insights and recommendations."},{"title":"SEO & Content Strategy","content":"Leverage AI for keyword research, content gap analysis, and SEO optimization of existing content. Build a data-driven content calendar that aligns with search trends and audience interests."},{"title":"Marketing Analytics & Reporting","content":"Use AI to consolidate marketing data from multiple channels into unified performance reports. Generate insights and recommendations that connect marketing activities to business outcomes."}]', '["Create high-quality, brand-consistent marketing content across multiple channels using AI","Implement AI-driven audience segmentation and personalization strategies","Analyze campaign performance with AI and make data-backed optimization decisions"]', '[{"title":"Multi-Channel Campaign Builder","description":"Use AI to create a complete mini-campaign including a blog post, three social media posts, and an email sequence for a provided product or service brief.","type":"hands-on"},{"title":"Campaign Performance Optimizer","description":"Analyze a sample campaign''s performance data using AI, identify three specific optimization opportunities, and draft revised copy for the underperforming elements.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered marketing for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 6, 'AI Customer Service', 'Chatbots & Support', 'Design and deploy AI-powered customer service solutions that improve response times and customer satisfaction. Learn to build chatbots, automate support workflows, and use AI to enhance human agent performance.', '[{"title":"Designing Conversational Flows","content":"Map out customer service scenarios and design conversational flows that feel natural and resolve issues efficiently. Learn to anticipate customer needs and build decision trees that handle common inquiries."},{"title":"Building AI Chatbots","content":"Create functional chatbots using no-code and low-code platforms with AI-powered natural language understanding. Configure intents, entities, and responses that accurately address customer questions."},{"title":"Knowledge Base Integration","content":"Connect AI chatbots to your company''s knowledge base, FAQs, and documentation for accurate, up-to-date responses. Learn to maintain and update the knowledge sources that power your AI support."},{"title":"Human-AI Handoff Strategies","content":"Design seamless escalation paths from AI chatbots to human agents with full conversation context. Set up triggers and thresholds that ensure customers reach a human when the AI cannot resolve their issue."},{"title":"Measuring Support Quality","content":"Track key metrics like resolution rate, customer satisfaction, and average handle time for AI-assisted support. Use analytics to continuously improve chatbot performance and identify training gaps."}]', '["Design conversational AI flows that effectively resolve common customer service scenarios","Build and configure a functional AI chatbot connected to a business knowledge base","Implement human-AI handoff strategies that maintain customer satisfaction during escalations"]', '[{"title":"Support Chatbot Builder","description":"Design and build a functional chatbot for a sample business that handles the five most common customer inquiries, including a smooth handoff to a human agent for complex issues.","type":"hands-on"},{"title":"Support Quality Analyzer","description":"Review a set of sample chatbot conversations, identify where the AI failed to resolve issues, and redesign the conversation flows to improve resolution rates.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered customer service for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 7, 'AI Presentation Builder', 'Slides & Visuals', 'Create professional presentations faster using AI tools for slide design, content structuring, and visual generation. Learn to transform ideas, data, and documents into compelling slide decks that engage your audience.', '[{"title":"Structuring Presentations with AI","content":"Use AI to outline and structure presentations based on your topic, audience, and goals. Learn frameworks for organizing information into clear narrative arcs that keep audiences engaged."},{"title":"AI Slide Design & Layout","content":"Leverage AI-powered design tools to create visually appealing slides with consistent branding and professional layouts. Automate formatting, color schemes, and typography for polished results every time."},{"title":"Visual Content Generation","content":"Generate charts, diagrams, icons, and illustrations using AI tools to enhance your slides. Learn to create custom visuals that communicate complex ideas more effectively than text alone."},{"title":"Data-to-Slides Automation","content":"Transform spreadsheets, reports, and documents into presentation-ready slides automatically using AI. Build workflows that convert raw data into visual stories with minimal manual effort."},{"title":"Presentation Polish & Delivery","content":"Use AI to refine speaker notes, generate talking points, and rehearse your delivery. Learn to create handouts, summaries, and follow-up materials from your presentation content automatically."}]', '["Structure and outline professional presentations using AI-driven content organization","Generate custom visuals, charts, and diagrams that enhance slide quality and clarity","Automate the transformation of data and documents into polished presentation decks"]', '[{"title":"Report-to-Deck Converter","description":"Take a provided business report and use AI to transform it into a ten-slide executive presentation with proper structure, key visuals, and speaker notes.","type":"hands-on"},{"title":"Visual Storytelling Workshop","description":"Create a five-slide data presentation using AI-generated charts and diagrams that tells a compelling story about a provided dataset without relying on bullet points.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered presentation creation for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 8, 'AI Email Management', 'Advanced Automation', 'Go beyond basic email with AI-powered systems that draft, prioritize, categorize, and respond to messages intelligently. Learn to build email workflows that keep your inbox organized and your communications professional.', '[{"title":"Intelligent Email Triage","content":"Set up AI-powered systems that automatically categorize, prioritize, and flag incoming emails based on urgency and relevance. Reduce inbox overwhelm by letting AI surface what matters most."},{"title":"AI-Assisted Email Drafting","content":"Use AI to draft professional replies, compose new messages, and adapt tone for different audiences and situations. Build templates that maintain your personal voice while saving significant writing time."},{"title":"Email Workflow Automation","content":"Create automated workflows for recurring email patterns like follow-ups, acknowledgments, and status updates. Set up triggers and rules that work alongside AI to handle routine correspondence."},{"title":"Email Analytics & Insights","content":"Analyze your email patterns to identify bottlenecks, response time issues, and communication gaps. Use AI-generated insights to optimize how you spend time on email throughout the day."},{"title":"Advanced Email Integrations","content":"Connect your email AI tools with calendars, CRMs, project management tools, and other business systems. Build end-to-end workflows where email actions trigger updates across your entire tool stack."}]', '["Configure AI-powered email triage systems that automatically prioritize and categorize incoming messages","Build automated email workflows for recurring communication patterns and follow-ups","Integrate email AI tools with other business systems for end-to-end workflow automation"]', '[{"title":"Inbox Zero Automation","description":"Set up an AI-powered email management system that categorizes your inbox into actionable groups, drafts responses for routine messages, and flags items requiring personal attention.","type":"hands-on"},{"title":"Follow-Up Workflow Builder","description":"Create an automated follow-up system that tracks unanswered emails, drafts contextually appropriate follow-up messages, and schedules them for optimal send times.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered email management for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 9, 'AI Meeting Assistant', 'Transcription & Action Items', 'Transform how you handle meetings with AI tools that transcribe conversations, extract action items, and generate follow-up documentation automatically. Learn to make every meeting more productive and accountable.', '[{"title":"AI Meeting Transcription","content":"Set up and use AI transcription tools that capture meeting conversations with speaker identification and timestamps. Learn to configure transcription for different meeting formats including in-person, virtual, and hybrid."},{"title":"Automated Action Item Extraction","content":"Use AI to automatically identify and extract action items, decisions, and deadlines from meeting transcripts. Learn to configure extraction rules that match your team''s communication style and meeting structure."},{"title":"Meeting Summary Generation","content":"Generate concise, structured meeting summaries that capture key discussion points, decisions made, and next steps. Customize summary formats for different audiences from executives to team members."},{"title":"Follow-Up Automation","content":"Build automated workflows that distribute meeting notes, assign action items in project management tools, and schedule follow-up reminders. Ensure nothing falls through the cracks after meetings end."},{"title":"Meeting Analytics & Optimization","content":"Analyze meeting patterns to identify inefficiencies such as excessive duration, recurring topics, and unresolved items. Use AI insights to improve meeting culture and reduce unnecessary meeting time."}]', '["Set up AI transcription systems that accurately capture meeting conversations with speaker attribution","Automatically extract action items, decisions, and deadlines from meeting transcripts","Build post-meeting workflows that distribute summaries and track follow-through on commitments"]', '[{"title":"Meeting-to-Actions Pipeline","description":"Process a sample meeting recording through an AI transcription tool, extract all action items with owners and deadlines, and format them as tasks ready for import into a project management tool.","type":"hands-on"},{"title":"Executive Summary Generator","description":"Take a lengthy meeting transcript and use AI to produce three versions: a one-paragraph executive summary, a detailed summary with decisions and actions, and a follow-up email draft for attendees.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered meeting management for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 10, 'Building Custom GPTs', 'Specialized Assistants', 'Learn to create custom AI assistants tailored to your specific business needs and workflows. This class covers designing, building, testing, and deploying specialized GPTs that encode your domain expertise and processes.', '[{"title":"Custom GPT Architecture","content":"Understand how custom GPTs work, including system prompts, knowledge bases, and action configurations. Learn the design principles that make custom assistants reliable and useful for specific business functions."},{"title":"Designing Your Assistant''s Persona","content":"Craft effective system prompts that define your GPT''s personality, expertise boundaries, and response style. Learn to encode business rules, terminology, and workflow logic into your assistant''s instructions."},{"title":"Knowledge Base Configuration","content":"Upload and configure reference documents, FAQs, and data sources that your custom GPT can draw from. Learn best practices for organizing knowledge to maximize retrieval accuracy and response quality."},{"title":"Actions & External Integrations","content":"Connect your custom GPT to external APIs and services to perform actions beyond text generation. Build integrations that allow your assistant to look up data, submit forms, and interact with business systems."},{"title":"Testing, Iteration & Deployment","content":"Systematically test your custom GPT across diverse scenarios to identify gaps and improve reliability. Learn to gather user feedback, iterate on your design, and share your assistant with your team."}]', '["Design and build a custom GPT with a well-crafted system prompt tailored to a specific business function","Configure knowledge bases and external integrations that extend your assistant''s capabilities","Test and iterate on custom GPTs using systematic evaluation methods to ensure reliability"]', '[{"title":"Department Assistant Builder","description":"Build a custom GPT for a specific business department that answers common questions, follows department-specific processes, and draws from uploaded reference documents.","type":"hands-on"},{"title":"Integration-Powered Assistant","description":"Extend your custom GPT by adding at least one external action or API integration that allows it to retrieve live data or perform a useful business operation.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master building custom GPTs for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 11, 'AI Project Management', 'Planning & Tracking', 'Enhance your project management capabilities with AI tools that assist in planning, scheduling, risk assessment, and progress tracking. Learn to deliver projects more predictably by leveraging AI for smarter decision-making throughout the project lifecycle.', '[{"title":"AI-Powered Project Planning","content":"Use AI to break down project goals into detailed work breakdown structures, estimate timelines, and identify dependencies. Generate comprehensive project plans from high-level requirements in a fraction of the usual time."},{"title":"Resource & Schedule Optimization","content":"Leverage AI to optimize resource allocation, identify scheduling conflicts, and suggest efficient task sequencing. Learn to balance workloads and adjust plans dynamically as conditions change."},{"title":"Risk Identification & Mitigation","content":"Apply AI tools to analyze project plans and historical data to surface potential risks and bottlenecks. Generate mitigation strategies and contingency plans proactively before issues impact delivery."},{"title":"Progress Tracking & Reporting","content":"Set up AI-enhanced dashboards and status reports that automatically track progress against milestones. Generate stakeholder updates and health assessments that highlight what matters most."},{"title":"Retrospectives & Continuous Improvement","content":"Use AI to analyze completed project data, identify patterns in delays and successes, and generate improvement recommendations. Build a knowledge base of lessons learned that informs future project planning."}]', '["Generate detailed project plans with timelines, dependencies, and resource allocations using AI","Identify and mitigate project risks proactively with AI-driven analysis","Create automated progress tracking dashboards and stakeholder reports with AI tools"]', '[{"title":"AI Project Planner","description":"Take a provided project brief and use AI to generate a complete project plan including work breakdown structure, timeline with milestones, resource assignments, and a risk register with mitigation strategies.","type":"hands-on"},{"title":"Status Report Automator","description":"Set up an AI-powered system that takes raw task completion data and generates a polished weekly status report with progress visuals, risk flags, and recommended next actions.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered project management for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 12, 'AI for Research', 'Finding & Synthesizing Info', 'Accelerate your research process with AI tools that find, evaluate, and synthesize information from multiple sources. Learn to produce thorough, well-sourced research outputs in a fraction of the time traditional methods require.', '[{"title":"AI-Powered Information Gathering","content":"Use AI search and retrieval tools to quickly find relevant information across academic papers, industry reports, and web sources. Learn to formulate queries that surface high-quality, authoritative results."},{"title":"Source Evaluation & Verification","content":"Apply critical evaluation frameworks with AI assistance to assess source credibility, detect bias, and verify claims. Learn to cross-reference findings and identify conflicting information that requires further investigation."},{"title":"Research Synthesis Techniques","content":"Use AI to synthesize findings from multiple sources into coherent narratives, comparison matrices, and thematic analyses. Learn to identify patterns and gaps across diverse research materials."},{"title":"Literature Reviews & Competitive Analysis","content":"Build comprehensive literature reviews and competitive analysis reports using AI to process large volumes of material. Generate structured overviews that highlight key findings, trends, and opportunities."},{"title":"Research Documentation & Citation","content":"Organize research outputs with proper attribution, citations, and source tracking using AI tools. Create shareable research briefs and reports that maintain academic and professional integrity."}]', '["Use AI tools to efficiently gather and evaluate information from diverse authoritative sources","Synthesize research findings from multiple sources into structured, actionable reports","Produce well-documented research outputs with proper source attribution and citation"]', '[{"title":"Competitive Landscape Report","description":"Use AI research tools to investigate a provided industry topic, gather information from at least ten sources, and produce a structured competitive analysis report with key findings and recommendations.","type":"hands-on"},{"title":"Research Synthesis Brief","description":"Take a collection of provided articles and reports on a topic, use AI to synthesize the key themes and conflicting viewpoints, and produce a two-page executive research brief with citations.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered research for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 13, 'AI Writing Pro', 'Advanced Copywriting', 'Elevate your writing with advanced AI techniques for professional copywriting, long-form content, and persuasive communication. Learn to produce polished, publication-ready content that maintains your unique voice while leveraging AI for speed and consistency.', '[{"title":"Voice & Tone Calibration","content":"Train AI tools to match your brand voice, writing style, and tone preferences across different content types. Learn to create style guides and reference samples that produce consistently on-brand outputs."},{"title":"Persuasive Writing Frameworks","content":"Apply proven copywriting frameworks like AIDA, PAS, and storytelling structures using AI assistance. Learn to craft compelling headlines, calls to action, and persuasive arguments that drive reader engagement."},{"title":"Long-Form Content Production","content":"Use AI to plan, draft, and refine long-form content such as white papers, case studies, and thought leadership articles. Master the workflow of outlining, section drafting, and iterative editing with AI support."},{"title":"Editing & Refinement with AI","content":"Leverage AI editing tools to improve clarity, eliminate jargon, fix grammar, and enhance readability scores. Learn to use AI as a sophisticated writing partner for revision rather than just initial drafting."},{"title":"Multi-Format Content Repurposing","content":"Transform a single piece of content into multiple formats including blog posts, social media threads, email newsletters, and video scripts. Maximize the value of every piece of content you create."}]', '["Calibrate AI writing tools to consistently produce content matching your brand voice and style","Apply persuasive copywriting frameworks with AI to create high-converting professional content","Repurpose single content pieces into multiple formats for maximum reach and efficiency"]', '[{"title":"Brand Voice Training","description":"Provide sample writing to an AI tool, configure it to match your style, then generate three different content pieces and evaluate how well each matches your established voice and tone.","type":"hands-on"},{"title":"Content Multiplication Workshop","description":"Take a single provided blog post and use AI to repurpose it into a LinkedIn article, an email newsletter, three social media posts, and a video script outline while maintaining consistent messaging.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master advanced AI-powered copywriting for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 14, 'AI Image Generation', 'Professional Visuals', 'Create professional-quality images for business use with AI generation tools like DALL-E, Midjourney, and Stable Diffusion. Learn prompting techniques, style control, and practical workflows for producing brand-consistent visual content.', '[{"title":"Image Generation Fundamentals","content":"Understand how AI image generation works and the capabilities of leading tools like DALL-E, Midjourney, and Stable Diffusion. Learn the strengths and limitations of each platform for different business use cases."},{"title":"Visual Prompt Engineering","content":"Master the art of writing image prompts that produce consistent, high-quality results with specific styles, compositions, and moods. Learn to use modifiers, negative prompts, and reference images to control outputs precisely."},{"title":"Brand-Consistent Visual Creation","content":"Develop techniques for generating images that align with your brand guidelines including colors, styles, and visual identity. Build prompt templates and style references that ensure visual consistency across all generated content."},{"title":"Practical Business Applications","content":"Apply AI image generation to real business needs including social media graphics, presentation visuals, product mockups, and marketing materials. Learn workflows for common professional visual tasks."},{"title":"Editing, Refinement & Legal Considerations","content":"Use AI inpainting, outpainting, and editing tools to refine generated images to professional standards. Understand usage rights, licensing, and legal considerations for AI-generated images in commercial contexts."}]', '["Write effective image generation prompts that produce consistent, professional-quality visual outputs","Create brand-consistent visual content using AI tools with proper style control and templates","Navigate the legal and ethical considerations of using AI-generated images in business contexts"]', '[{"title":"Brand Visual Kit Generator","description":"Create a set of five brand-consistent social media graphics for a provided brand brief using AI image generation, ensuring consistent style, color palette, and visual identity across all images.","type":"hands-on"},{"title":"Product Mockup Studio","description":"Generate three professional product mockup images from text descriptions, then use AI editing tools to refine one image with specific modifications like background changes and text overlays.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI image generation for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 15, 'AI Video Creation', 'Scripts & Production', 'Harness AI tools to streamline video production from scriptwriting and storyboarding to editing and post-production. Learn to create professional video content faster and more affordably using the latest AI-powered video tools.', '[{"title":"AI Scriptwriting & Storyboarding","content":"Use AI to generate video scripts, shot lists, and storyboards based on your content goals and audience. Learn to structure video narratives that hold viewer attention and deliver your message effectively."},{"title":"AI Video Generation Tools","content":"Explore AI-powered video creation platforms that generate video content from text, images, and templates. Understand the capabilities and limitations of tools like Synthesia, Runway, and similar platforms."},{"title":"Voiceover & Audio Production","content":"Generate professional voiceovers using AI text-to-speech tools with natural-sounding voices and multiple language options. Learn to select appropriate voice styles and integrate audio seamlessly with visual content."},{"title":"AI-Assisted Video Editing","content":"Use AI editing tools to automate tedious post-production tasks like cutting, transitions, color correction, and caption generation. Learn to produce polished final cuts in a fraction of the traditional editing time."},{"title":"Video Distribution & Optimization","content":"Leverage AI to generate thumbnails, titles, descriptions, and tags optimized for different platforms. Learn to repurpose video content across YouTube, social media, and internal communications channels."}]', '["Write effective video scripts and storyboards using AI tools for various business content needs","Produce professional video content using AI generation, voiceover, and editing tools","Optimize video content for distribution across multiple platforms using AI-powered tools"]', '[{"title":"Explainer Video Creator","description":"Use AI tools to create a complete 60-second explainer video for a provided product or concept, including script, AI-generated visuals, voiceover, and captions.","type":"hands-on"},{"title":"Video Repurposing Pipeline","description":"Take a provided long-form video transcript and use AI to create a short promotional clip script, three social media teaser descriptions, and an optimized YouTube title and description.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered video creation for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 16, 'AI for Sales', 'Lead Scoring & Outreach', 'Boost your sales performance with AI tools that score leads, personalize outreach, and optimize your sales pipeline. Learn to close more deals by focusing your energy on the right prospects with the right message at the right time.', '[{"title":"AI-Powered Lead Scoring","content":"Set up AI models that analyze prospect data and behavior to prioritize leads by likelihood to convert. Learn to define scoring criteria and integrate AI scoring into your existing CRM workflow."},{"title":"Personalized Outreach at Scale","content":"Use AI to research prospects, personalize email sequences, and craft tailored messaging for different buyer personas. Generate customized outreach that feels one-to-one even when operating at volume."},{"title":"Sales Intelligence & Research","content":"Leverage AI tools to gather competitive intelligence, monitor trigger events, and surface relevant insights before sales conversations. Walk into every meeting better prepared than your competition."},{"title":"Pipeline Analysis & Forecasting","content":"Apply AI analytics to your sales pipeline to identify stalled deals, predict close rates, and forecast revenue accurately. Learn to use data-driven insights to focus coaching and resources where they matter most."},{"title":"Sales Content & Proposal Generation","content":"Use AI to quickly generate proposals, case studies, ROI calculators, and sales collateral customized for each prospect. Reduce the time from opportunity identification to proposal delivery."}]', '["Implement AI-powered lead scoring systems that prioritize prospects by conversion likelihood","Create personalized, AI-generated outreach sequences that maintain authenticity at scale","Analyze sales pipeline data with AI to improve forecasting accuracy and identify coaching opportunities"]', '[{"title":"Lead Scoring Model Builder","description":"Design an AI-powered lead scoring system for a sample business, define the scoring criteria, process a provided list of leads, and rank them with explanations for each score.","type":"hands-on"},{"title":"Personalized Outreach Sequence","description":"Research five provided prospect profiles using AI, then create a personalized three-email outreach sequence for each prospect that references their specific business context and pain points.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI-powered sales techniques for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 17, 'AI Workflow Design', 'Zapier, Make & Integrations', 'Design and build AI-powered automation workflows that connect your business tools into seamless, intelligent processes. Learn to use platforms like Zapier and Make to create integrations that save hours of manual work every week.', '[{"title":"Workflow Design Principles","content":"Learn a systematic approach to mapping business processes and identifying integration opportunities between tools. Understand triggers, actions, filters, and conditional logic that form the building blocks of effective automations."},{"title":"Building with Zapier","content":"Create multi-step AI-powered automations in Zapier that connect popular business tools with intelligent processing. Learn to use AI actions within Zaps for tasks like content generation, data transformation, and smart routing."},{"title":"Building with Make","content":"Design visual workflow automations in Make that handle complex branching logic and data transformations. Leverage Make''s advanced features for scenarios that require more sophisticated processing than simple trigger-action pairs."},{"title":"AI-Enhanced Integration Patterns","content":"Implement common AI integration patterns including content processing pipelines, smart notification systems, and automated reporting workflows. Learn reusable patterns you can adapt across many different business processes."},{"title":"Monitoring, Error Handling & Scaling","content":"Set up monitoring, error handling, and alerting for your automation workflows to ensure reliability. Learn to troubleshoot failed runs, handle edge cases, and scale your automations as usage grows."}]', '["Design end-to-end automation workflows that connect multiple business tools with AI processing","Build functional AI-powered automations using Zapier and Make for common business processes","Implement error handling and monitoring to ensure automation reliability at scale"]', '[{"title":"Content Pipeline Automator","description":"Build a working automation that takes a new content idea from a form, uses AI to generate a draft, routes it for review, and publishes the approved version to a designated platform.","type":"hands-on"},{"title":"Smart CRM Workflow","description":"Create an automation that monitors incoming leads, uses AI to enrich and score them, routes high-priority leads to the sales team with personalized context, and logs all activities in the CRM.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI workflow design and integrations for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 18, 'AI Strategy for Teams', 'Organizational AI Adoption', 'Develop a practical strategy for introducing and scaling AI adoption across your team or organization. Learn to identify high-impact use cases, manage change effectively, and build an AI-ready culture that drives measurable business results.', '[{"title":"Assessing AI Readiness","content":"Evaluate your organization''s current AI maturity level across technology, skills, culture, and data dimensions. Identify gaps and prioritize areas where investment will yield the greatest return."},{"title":"Identifying High-Impact Use Cases","content":"Apply a structured framework to discover and prioritize AI use cases based on business value, feasibility, and strategic alignment. Learn to build a phased roadmap that delivers quick wins while building toward transformational capabilities."},{"title":"Change Management for AI","content":"Address common resistance to AI adoption with proven change management strategies tailored to technology transformation. Learn to communicate AI''s benefits, address fears about job displacement, and build enthusiasm through early successes."},{"title":"Building AI Skills & Culture","content":"Design training programs and learning pathways that upskill your team''s AI capabilities progressively. Create an environment where experimentation is encouraged and AI literacy becomes a core organizational competency."},{"title":"Governance & Scaling","content":"Establish governance frameworks including usage policies, data guidelines, and quality standards for AI use across the organization. Plan for scaling successful pilots into enterprise-wide capabilities with appropriate oversight."}]', '["Assess organizational AI readiness and create a prioritized adoption roadmap with quick wins","Apply change management principles to drive enthusiastic AI adoption across teams","Establish AI governance frameworks that enable innovation while maintaining appropriate oversight"]', '[{"title":"AI Readiness Assessment","description":"Conduct a comprehensive AI readiness assessment for a sample organization using the provided framework, then create a prioritized twelve-month adoption roadmap with three phases.","type":"hands-on"},{"title":"AI Champions Program Design","description":"Design an internal AI champions program including selection criteria, training curriculum, success metrics, and a communication plan to drive grassroots AI adoption across departments.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI strategy and organizational adoption for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 19, 'AI Ethics at Work', 'Responsible Use & Governance', 'Navigate the ethical challenges of using AI in professional settings with confidence and responsibility. Learn to identify bias, protect privacy, ensure transparency, and establish governance practices that build trust with stakeholders.', '[{"title":"Understanding AI Bias","content":"Learn how bias enters AI systems through training data, prompt design, and application context. Develop practical skills for detecting and mitigating bias in the AI outputs you use for business decisions."},{"title":"Privacy & Data Protection","content":"Understand the privacy implications of sharing business and customer data with AI tools. Learn best practices for data handling, anonymization, and compliance with regulations like GDPR and CCPA when using AI services."},{"title":"Transparency & Disclosure","content":"Develop clear policies for when and how to disclose AI involvement in content creation, decision-making, and customer interactions. Learn to balance transparency with practical business considerations."},{"title":"Intellectual Property & Ownership","content":"Navigate the evolving landscape of intellectual property rights related to AI-generated content. Understand copyright considerations, terms of service implications, and best practices for protecting your organization''s IP."},{"title":"Building an AI Ethics Framework","content":"Create a practical AI ethics framework for your organization that covers acceptable use, review processes, and escalation procedures. Learn to balance innovation with responsibility in a way that builds stakeholder trust."}]', '["Identify and mitigate common forms of AI bias in business applications and decision-making","Implement data privacy best practices when using AI tools with sensitive business information","Create a practical AI ethics and governance framework tailored to your organization''s needs"]', '[{"title":"Bias Audit Exercise","description":"Analyze a set of AI-generated outputs for a hiring, marketing, and customer service scenario, identify instances of potential bias, and propose specific mitigation strategies for each.","type":"hands-on"},{"title":"AI Usage Policy Builder","description":"Draft a comprehensive AI acceptable use policy for a sample organization covering data handling, disclosure requirements, prohibited uses, and a review process for new AI tool adoption.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master AI ethics and responsible use for professional settings. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('intermediate', 20, 'AI Business Case', 'Measuring AI ROI', 'Learn to build compelling business cases for AI investments by quantifying costs, measuring returns, and communicating value to stakeholders. This class gives you the financial and analytical tools to justify and prioritize AI initiatives with confidence.', '[{"title":"AI Cost Analysis","content":"Break down the true costs of AI adoption including tool subscriptions, training time, integration effort, and ongoing maintenance. Learn to create realistic cost models that account for both direct and indirect expenses."},{"title":"Measuring AI Value & ROI","content":"Define and track key metrics that demonstrate AI''s business impact including time savings, quality improvements, revenue growth, and cost reduction. Learn multiple ROI calculation methods appropriate for different types of AI initiatives."},{"title":"Building the Business Case","content":"Structure compelling AI investment proposals that speak the language of executives and finance teams. Learn to present costs, benefits, risks, and timelines in formats that facilitate confident decision-making."},{"title":"Pilot Design & Success Metrics","content":"Design AI pilot programs with clear success criteria, measurement plans, and go/no-go decision frameworks. Learn to scope pilots that are small enough to execute quickly but meaningful enough to prove value."},{"title":"Scaling & Long-Term Value Tracking","content":"Plan for scaling successful AI pilots into permanent business capabilities with sustained value tracking. Build dashboards and reporting cadences that keep stakeholders informed and maintain support for ongoing AI investment."}]', '["Calculate the total cost of AI adoption including direct, indirect, and hidden expenses","Design AI pilot programs with clear success metrics and ROI measurement frameworks","Build executive-ready business cases that effectively communicate AI investment value and risk"]', '[{"title":"AI ROI Calculator","description":"Build a comprehensive ROI model for a provided AI use case that accounts for all costs, quantifies expected benefits across three scenarios, and calculates payback period and net present value.","type":"hands-on"},{"title":"Executive Business Case Presentation","description":"Create a complete AI investment business case for a sample initiative including problem statement, proposed solution, cost-benefit analysis, pilot plan, risk assessment, and a one-page executive summary.","type":"hands-on"}]', 'You are an AI tutor helping an intermediate learner master building AI business cases and measuring ROI for professional use. Provide practical examples, workflow tips, and real-world business applications. Assume the student is comfortable with basic AI tools.', 30);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 1, 'AI Dev Environment Setup', 'Cursor, Copilot & AI IDEs', 'Learn how to configure and optimize AI-powered development environments including Cursor, GitHub Copilot, and other intelligent IDEs. Master the settings, keybindings, and workflows that maximize your productivity with AI coding assistants.', '[{"title":"AI IDE Landscape","content":"Survey the current ecosystem of AI-powered development environments including Cursor, GitHub Copilot, Cody, and others. Compare features, pricing, and ideal use cases for each tool."},{"title":"Cursor Deep Dive","content":"Install and configure Cursor with optimal settings for advanced development workflows. Learn to use Cursor''s chat, composer, and inline editing features effectively."},{"title":"GitHub Copilot Configuration","content":"Set up GitHub Copilot across multiple editors and configure suggestion behavior and context awareness. Master Copilot Chat and workspace-level prompt engineering."},{"title":"Custom AI Workflows","content":"Create personalized AI coding workflows by combining multiple tools and configuring context files like .cursorrules. Build reusable prompt templates and snippets for common development tasks."},{"title":"Performance & Privacy","content":"Optimize AI tool performance by managing context windows, token usage, and response quality. Configure privacy settings and understand data handling policies for enterprise environments."}]', '["Configure and optimize at least three AI-powered development environments for professional use","Create custom AI workflow configurations including context files and prompt templates","Evaluate and select the right AI coding tools for specific project requirements"]', '[{"title":"AI IDE Benchmark","description":"Set up Cursor, Copilot, and one additional AI IDE. Complete the same coding task in each environment, documenting speed, accuracy, and quality of AI suggestions. Write a comparison report.","type":"hands-on"},{"title":"Custom Workflow Builder","description":"Create a .cursorrules file and a set of reusable prompt templates for a real project. Configure keybindings and settings to optimize your personal AI-assisted development workflow.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn AI development environment setup for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 2, 'Code Completion Mastery', 'Maximizing AI Suggestions', 'Master the art of getting high-quality code completions from AI assistants by understanding how context, naming conventions, and prompt structure affect suggestions. Learn advanced techniques for steering AI completions toward production-ready code.', '[{"title":"How Code Completion Works","content":"Understand the technical architecture behind AI code completion including tokenization, context windows, and model inference. Learn how different models prioritize file context, open tabs, and recent edits."},{"title":"Context Engineering","content":"Master techniques for providing optimal context to AI code completion engines through strategic file organization and naming. Learn how comments, type annotations, and function signatures dramatically improve suggestion quality."},{"title":"Multi-Line & Function-Level Completion","content":"Go beyond single-line suggestions to generate entire functions, classes, and modules with AI assistance. Learn to structure your prompts and code scaffolding to get coherent multi-line completions."},{"title":"Language-Specific Strategies","content":"Apply tailored completion strategies for Python, TypeScript, Rust, Go, and other popular languages. Understand how language features like type systems and decorators influence AI suggestion quality."},{"title":"Evaluating & Refining Suggestions","content":"Develop a critical eye for AI-generated code by identifying common pitfalls like hallucinated APIs and subtle bugs. Build a personal feedback loop to continuously improve the quality of completions you receive."}]', '["Engineer optimal code context to consistently receive high-quality AI completions across multiple languages","Generate production-ready multi-line completions for functions, classes, and complex logic blocks","Identify and correct common AI completion errors including hallucinated APIs and logic flaws"]', '[{"title":"Completion Quality Lab","description":"Write a series of increasingly complex functions using only AI completions. Start with utility functions, progress to algorithm implementations, and finish with a class hierarchy. Score each completion for correctness and quality.","type":"hands-on"},{"title":"Context Window Experiment","description":"Take a poorly-performing AI completion scenario and systematically improve it by adding type hints, docstrings, variable names, and surrounding context. Document how each change affects completion quality.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn code completion mastery for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 3, 'Debugging with AI', 'Finding & Fixing Bugs Faster', 'Leverage AI tools to dramatically accelerate your debugging workflow, from interpreting error messages to tracing complex logic bugs across codebases. Learn systematic approaches to using AI for root cause analysis, fix generation, and regression prevention.', '[{"title":"AI-Assisted Error Analysis","content":"Use AI to interpret stack traces, error messages, and crash logs across different languages and frameworks. Learn prompting techniques that help AI pinpoint the root cause rather than just the symptom."},{"title":"Logic Bug Detection","content":"Apply AI tools to detect subtle logic errors, off-by-one mistakes, race conditions, and edge cases that traditional debugging misses. Use AI to generate test cases that expose hidden bugs in existing code."},{"title":"Interactive Debugging Sessions","content":"Conduct real-time debugging sessions with AI by sharing code context, variable states, and execution flow. Learn to use AI chat interfaces effectively to narrow down bugs through iterative conversation."},{"title":"Codebase-Wide Bug Hunting","content":"Use AI to analyze patterns across large codebases to find systemic issues like memory leaks, security vulnerabilities, and performance bottlenecks. Leverage AI-powered code review to catch bugs before they reach production."},{"title":"Fix Generation & Verification","content":"Generate reliable fixes using AI and verify them through automated testing and reasoning validation. Build workflows that prevent regressions by having AI suggest related test cases for every fix."}]', '["Use AI tools to perform root cause analysis on complex bugs across multi-file codebases","Generate and verify reliable bug fixes using AI-assisted debugging workflows","Build systematic AI debugging processes that reduce mean time to resolution"]', '[{"title":"Bug Bash Challenge","description":"Work through a series of intentionally buggy code samples spanning race conditions, memory leaks, and logic errors. Use AI to identify each bug, explain the root cause, and generate a verified fix with test coverage.","type":"hands-on"},{"title":"Production Debugging Simulation","description":"Given a simulated production incident with logs, stack traces, and user reports, use AI to perform root cause analysis and generate a hotfix. Document your AI-assisted debugging process step by step.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn AI-assisted debugging for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 4, 'AI-Powered Testing', 'Auto-Generated Test Suites', 'Harness AI to generate comprehensive test suites including unit tests, integration tests, and end-to-end tests with meaningful assertions and edge case coverage. Learn to use AI for test-driven development, mutation testing, and continuous test maintenance.', '[{"title":"AI Test Generation Fundamentals","content":"Understand how AI generates test cases by analyzing code structure, function signatures, and expected behavior. Learn prompting strategies that produce tests with meaningful assertions rather than trivial pass-through checks."},{"title":"Unit Test Generation at Scale","content":"Generate comprehensive unit test suites for existing codebases using AI tools like Copilot and Cursor. Master techniques for handling mocks, fixtures, and dependency injection in AI-generated tests."},{"title":"Integration & E2E Test Creation","content":"Use AI to generate integration tests that verify component interactions and end-to-end tests that simulate real user workflows. Learn to prompt AI for proper test setup, teardown, and environment configuration."},{"title":"Test-Driven Development with AI","content":"Apply AI assistance to TDD workflows by generating failing tests from specifications before writing implementation code. Use AI to refine test cases as requirements evolve and to maintain test-specification alignment."},{"title":"Test Quality & Maintenance","content":"Evaluate AI-generated test quality using mutation testing and code coverage analysis. Build automated workflows for keeping test suites current as codebases evolve using AI-powered test maintenance."}]', '["Generate comprehensive test suites with meaningful assertions and edge case coverage using AI tools","Apply AI-assisted test-driven development to build well-tested features from specifications","Evaluate and improve AI-generated test quality through mutation testing and coverage analysis"]', '[{"title":"Test Suite Generator","description":"Take an untested module with at least five functions and use AI to generate a complete test suite including unit tests, edge cases, and integration tests. Achieve at least 90% code coverage with meaningful assertions.","type":"hands-on"},{"title":"TDD with AI Partner","description":"Implement a new feature using strict TDD with AI assistance. Write failing tests first using AI-generated test cases from a specification, then implement code to pass them. Document how AI accelerated the TDD cycle.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn AI-powered testing for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 5, 'Building Web Apps with AI', 'Full-Stack Development', 'Build complete full-stack web applications using AI coding assistants to accelerate every phase from scaffolding to deployment. Master AI-driven development workflows for React, Next.js, and modern web frameworks.', '[{"title":"AI-Powered Project Scaffolding","content":"Use AI to generate complete project structures including configuration files, folder hierarchies, and boilerplate code for modern web stacks. Compare AI scaffolding approaches across Next.js, Remix, and other frameworks."},{"title":"Frontend Development with AI","content":"Build responsive, accessible UI components using AI-assisted development with React and modern CSS frameworks. Leverage AI to generate complex state management, form handling, and client-side routing logic."},{"title":"Backend & API Layer","content":"Use AI to build server-side logic including API routes, middleware, authentication, and data validation. Generate database queries, ORM models, and server-side rendering logic with AI assistance."},{"title":"Full-Stack Integration","content":"Connect frontend and backend layers using AI to generate type-safe API clients, data fetching hooks, and real-time communication. Build complete CRUD workflows with AI handling the repetitive integration code."},{"title":"Deployment & Production Readiness","content":"Use AI to configure build pipelines, environment variables, and deployment settings for platforms like Vercel and AWS. Generate production optimizations including caching strategies, error boundaries, and monitoring setup."}]', '["Build a complete full-stack web application from scaffold to deployment using AI-assisted development","Generate production-ready frontend components with proper state management, accessibility, and responsive design","Implement secure backend logic including authentication, API routes, and database integration using AI tools"]', '[{"title":"Full-Stack App Sprint","description":"Build a complete task management web application with authentication, CRUD operations, and real-time updates using AI assistance for every layer. Deploy to a cloud platform with proper environment configuration.","type":"hands-on"},{"title":"AI Pair Programming Session","description":"Take an existing web application and add a major feature (e.g., search, notifications, or dashboards) using AI as your pair programmer. Document every AI interaction and measure time saved versus manual development.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn full-stack web development with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 6, 'API Development with AI', 'Design & Build APIs', 'Design and implement robust RESTful and GraphQL APIs using AI tools to accelerate schema design, endpoint generation, and documentation. Learn AI-driven approaches to API versioning, rate limiting, and contract testing.', '[{"title":"AI-Assisted API Design","content":"Use AI to design API schemas following REST and GraphQL best practices including resource modeling and relationship mapping. Generate OpenAPI specifications and GraphQL schemas from natural language descriptions of your domain."},{"title":"Endpoint Generation & Implementation","content":"Rapidly generate API endpoint implementations with proper request validation, error handling, and response formatting using AI. Build complete CRUD APIs with pagination, filtering, and sorting through AI-assisted development."},{"title":"Authentication & Authorization","content":"Implement secure API authentication using JWT, OAuth 2.0, and API keys with AI-generated boilerplate and middleware. Use AI to design role-based access control systems and generate authorization logic."},{"title":"API Documentation & Testing","content":"Generate comprehensive API documentation from code using AI-powered tools and OpenAPI generators. Create API test suites including contract tests, load tests, and integration tests with AI assistance."},{"title":"Advanced API Patterns","content":"Implement advanced patterns like rate limiting, caching, webhooks, and API versioning with AI-generated code. Use AI to design event-driven architectures and build real-time API features with WebSockets."}]', '["Design and generate complete API schemas using AI from natural language domain descriptions","Implement secure, well-documented APIs with proper authentication, validation, and error handling","Build advanced API features including rate limiting, versioning, and real-time capabilities using AI tools"]', '[{"title":"API from Spec","description":"Write a natural language description of a domain (e.g., e-commerce or project management), then use AI to generate an OpenAPI spec, implement all endpoints, add authentication, and produce interactive documentation.","type":"hands-on"},{"title":"GraphQL API Builder","description":"Design and build a GraphQL API with queries, mutations, subscriptions, and proper authorization using AI assistance. Include N+1 query prevention, caching, and comprehensive resolver testing.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn API development with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 7, 'Database Design with AI', 'Schema & Query Optimization', 'Use AI to design normalized database schemas, write optimized queries, and implement migration strategies for both SQL and NoSQL databases. Master AI-assisted performance tuning through index optimization, query planning, and data modeling.', '[{"title":"AI-Driven Schema Design","content":"Use AI to generate normalized database schemas from natural language descriptions of business domains and relationships. Learn to evaluate AI-suggested schemas for proper normalization, indexing, and constraint design."},{"title":"Query Generation & Optimization","content":"Generate complex SQL and NoSQL queries using AI and learn to prompt for optimized execution plans. Use AI to rewrite slow queries, add appropriate indexes, and analyze query performance bottlenecks."},{"title":"Migration Strategy & Management","content":"Use AI to generate database migration scripts for schema changes, data transformations, and version management. Build safe rollback strategies and zero-downtime migration plans with AI assistance."},{"title":"NoSQL & Hybrid Approaches","content":"Design document stores, key-value databases, and graph databases using AI-assisted modeling techniques. Learn when to use SQL versus NoSQL and how AI can help design hybrid data architectures."},{"title":"Performance Tuning & Monitoring","content":"Apply AI to analyze slow query logs, suggest index optimizations, and identify database performance bottlenecks. Build monitoring dashboards and alerting systems for database health using AI-generated configurations."}]', '["Design normalized, properly indexed database schemas from domain descriptions using AI tools","Generate and optimize complex database queries with AI-assisted performance analysis","Plan and execute safe database migrations and schema evolution strategies with AI assistance"]', '[{"title":"Schema Design Challenge","description":"Given a complex business domain description (e.g., a healthcare system or logistics platform), use AI to design a complete database schema with tables, relationships, indexes, and constraints. Benchmark query performance and optimize.","type":"hands-on"},{"title":"Query Optimization Lab","description":"Take a set of slow-performing queries against a sample database and use AI to analyze execution plans, suggest indexes, rewrite queries, and measure the performance improvement of each optimization.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn database design and optimization with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 8, 'AI for Frontend Development', 'Components & Responsive Design', 'Build sophisticated, accessible frontend components and responsive layouts using AI to accelerate design-to-code workflows. Master AI-assisted CSS generation, component architecture, and cross-browser optimization.', '[{"title":"Component Architecture with AI","content":"Use AI to design and generate reusable component libraries following atomic design principles and composition patterns. Build component hierarchies with proper prop typing, state management, and accessibility attributes."},{"title":"AI-Powered Styling","content":"Generate responsive CSS, Tailwind configurations, and styled-components using AI tools for rapid UI development. Use AI to create design system tokens, animation libraries, and theme configurations."},{"title":"Design-to-Code Workflows","content":"Convert design mockups and wireframes into functional code using AI-powered tools like v0 and screenshot-to-code systems. Learn to refine AI-generated UI code for production quality, performance, and maintainability."},{"title":"State Management & Data Flow","content":"Implement complex frontend state management patterns using AI-generated code for Redux, Zustand, or React Context. Use AI to build data fetching layers, caching strategies, and optimistic UI update patterns."},{"title":"Accessibility & Cross-Browser","content":"Use AI to audit and improve component accessibility including ARIA attributes, keyboard navigation, and screen reader support. Generate cross-browser compatibility fixes and progressive enhancement strategies with AI assistance."}]', '["Build production-ready component libraries with proper typing, accessibility, and responsive behavior using AI","Convert design mockups to functional, maintainable frontend code using AI-powered design-to-code tools","Implement complex state management and data fetching patterns with AI-generated architecture"]', '[{"title":"Component Library Sprint","description":"Use AI to build a complete component library with at least 10 components including buttons, forms, modals, tables, and navigation. Each component must be accessible, responsive, themed, and fully typed with TypeScript.","type":"hands-on"},{"title":"Design-to-Code Challenge","description":"Take a provided design mockup and use AI tools to convert it into a pixel-perfect, responsive implementation. Add interactivity, animations, and proper state management. Compare AI output quality across different tools.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn frontend development with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 9, 'AI for Backend Logic', 'Server-Side Architecture', 'Design and implement scalable server-side architectures using AI to generate microservices, middleware, and business logic layers. Master AI-driven approaches to concurrency, caching, message queues, and distributed system patterns.', '[{"title":"Architecture Design with AI","content":"Use AI to design server-side architectures including monoliths, microservices, and serverless patterns based on requirements analysis. Generate architecture decision records and system diagrams from natural language descriptions."},{"title":"Business Logic Generation","content":"Implement complex business rules, validation pipelines, and domain logic using AI-assisted development. Use AI to generate service layers with proper error handling, logging, and transaction management."},{"title":"Middleware & Pipeline Patterns","content":"Build middleware chains, request pipelines, and interceptor patterns using AI-generated code for Express, FastAPI, or similar frameworks. Implement cross-cutting concerns like authentication, rate limiting, and request logging with AI."},{"title":"Concurrency & Async Patterns","content":"Use AI to implement concurrent processing with worker threads, async queues, and event-driven architectures. Generate code for handling race conditions, deadlocks, and resource contention with proper synchronization."},{"title":"Caching & Performance","content":"Implement multi-layer caching strategies using Redis, in-memory caches, and CDN configurations with AI assistance. Use AI to design cache invalidation logic, connection pooling, and database query optimization."}]', '["Design scalable server-side architectures using AI to evaluate trade-offs between monolith, microservice, and serverless patterns","Implement robust business logic layers with proper error handling, validation, and transaction management using AI","Build high-performance backend systems with AI-assisted caching, concurrency, and async processing patterns"]', '[{"title":"Microservice Builder","description":"Design and implement a set of three interconnected microservices with API gateway, service discovery, and inter-service communication using AI assistance. Include health checks, circuit breakers, and centralized logging.","type":"hands-on"},{"title":"Performance Optimization Sprint","description":"Take a deliberately slow backend application and use AI to identify bottlenecks, implement caching layers, optimize database queries, add connection pooling, and measure the performance improvements at each step.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn backend architecture with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 10, 'Version Control with AI', 'Git Workflows & Code Review', 'Supercharge your Git workflows using AI for intelligent commit messages, automated code reviews, and merge conflict resolution. Learn to integrate AI into pull request processes and maintain high code quality across teams.', '[{"title":"AI-Powered Commit Messages","content":"Generate meaningful, conventional commit messages using AI tools that analyze staged changes and project context. Configure automated commit message generation in your development workflow."},{"title":"Intelligent Code Review","content":"Use AI tools to perform automated code reviews that catch bugs, style violations, and architectural issues. Configure AI review bots for pull requests and learn to calibrate their sensitivity and focus areas."},{"title":"Merge Conflict Resolution","content":"Leverage AI to understand and resolve complex merge conflicts by analyzing the intent of divergent changes. Use AI to suggest optimal conflict resolutions that preserve functionality from both branches."},{"title":"Branch Strategy & Workflow Design","content":"Use AI to design Git branching strategies appropriate for team size, release cadence, and project complexity. Generate Git hooks, automation scripts, and CI triggers using AI-assisted development."},{"title":"Code Quality Automation","content":"Build automated code quality pipelines using AI-powered linting, formatting, and static analysis tools. Configure pre-commit hooks and CI checks that use AI to enforce coding standards and best practices."}]', '["Generate meaningful, standards-compliant commit messages and changelogs using AI analysis of code changes","Configure AI-powered automated code review systems for pull requests that catch bugs and style issues","Resolve complex merge conflicts using AI tools that understand the intent behind divergent code changes"]', '[{"title":"AI Code Review Pipeline","description":"Set up a complete AI-powered code review pipeline for a repository including automated PR reviews, commit message validation, and code quality checks. Configure sensitivity levels and custom rules for your project''s standards.","type":"hands-on"},{"title":"Conflict Resolution Workshop","description":"Work through a series of increasingly complex merge conflicts using AI assistance. Include scenarios with refactored code, moved files, and concurrent feature development. Document AI''s accuracy and limitations.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn version control with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 11, 'AI DevOps', 'CI/CD & Deployment Automation', 'Automate your entire CI/CD pipeline using AI to generate build configurations, deployment scripts, and infrastructure-as-code templates. Master AI-driven approaches to container orchestration, monitoring, and incident response.', '[{"title":"CI/CD Pipeline Generation","content":"Use AI to generate complete CI/CD pipeline configurations for GitHub Actions, GitLab CI, and Jenkins from project requirements. Build multi-stage pipelines with testing, security scanning, and deployment gates using AI."},{"title":"Infrastructure as Code with AI","content":"Generate Terraform, CloudFormation, and Pulumi templates using AI for cloud infrastructure provisioning. Use AI to design network topologies, security groups, and resource configurations following best practices."},{"title":"Container Orchestration","content":"Build Docker configurations and Kubernetes manifests using AI-assisted development for container orchestration. Generate Helm charts, deployment strategies, and auto-scaling configurations with AI tools."},{"title":"Monitoring & Observability","content":"Use AI to design and implement monitoring stacks with metrics, logging, and distributed tracing. Generate alerting rules, dashboard configurations, and runbook templates using AI assistance."},{"title":"Incident Response Automation","content":"Build AI-powered incident response workflows including automated diagnostics, rollback triggers, and communication templates. Use AI to analyze production incidents and generate post-mortem documentation."}]', '["Generate complete CI/CD pipeline configurations using AI for multiple platforms including GitHub Actions and GitLab CI","Build infrastructure-as-code templates and container orchestration manifests using AI-assisted development","Design monitoring, alerting, and incident response systems with AI-generated configurations and runbooks"]', '[{"title":"Pipeline Builder","description":"Use AI to generate a complete CI/CD pipeline for a full-stack application including build, test, security scan, staging deployment, and production release with manual approval gates. Deploy to a real cloud environment.","type":"hands-on"},{"title":"Infrastructure Sprint","description":"Generate a complete infrastructure-as-code setup for a production application including networking, compute, database, monitoring, and alerting using AI. Include auto-scaling, backup strategies, and disaster recovery.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn DevOps with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 12, 'Building Chatbots', 'Conversational AI Applications', 'Build production-ready chatbot applications using modern LLM APIs, conversation management, and natural language understanding techniques. Learn to design conversational flows, handle context, and deploy chatbots across multiple platforms.', '[{"title":"Chatbot Architecture","content":"Design chatbot architectures using LLM APIs including OpenAI, Anthropic, and open-source models with proper abstraction layers. Understand conversation state management, context windows, and token optimization strategies."},{"title":"Conversation Design","content":"Build effective conversation flows with intent recognition, entity extraction, and fallback handling using AI. Design multi-turn conversations that maintain context and handle topic switches gracefully."},{"title":"RAG-Powered Chatbots","content":"Implement Retrieval-Augmented Generation to give chatbots access to custom knowledge bases and documentation. Build vector search pipelines, chunk documents effectively, and manage retrieval quality."},{"title":"Tool Use & Function Calling","content":"Implement tool use and function calling to let chatbots interact with external APIs, databases, and services. Build safe execution environments and handle tool errors gracefully in conversation flows."},{"title":"Deployment & Platform Integration","content":"Deploy chatbots to web, Slack, Discord, and other platforms with proper authentication and rate limiting. Implement conversation logging, analytics, and continuous improvement pipelines."}]', '["Build production-ready chatbots using LLM APIs with proper conversation management and context handling","Implement RAG systems that give chatbots accurate access to custom knowledge bases","Deploy chatbots across multiple platforms with tool use, analytics, and continuous improvement"]', '[{"title":"Knowledge Base Chatbot","description":"Build a RAG-powered chatbot that answers questions about a documentation set. Implement document chunking, vector search, conversation memory, and source citation. Deploy to a web interface with conversation logging.","type":"hands-on"},{"title":"Tool-Using Assistant","description":"Create a chatbot that can perform real actions like querying databases, calling APIs, and managing files through function calling. Implement proper error handling, confirmation flows, and safety guardrails.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn chatbot development for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 13, 'AI Agents Fundamentals', 'Understanding Autonomous Agents', 'Understand the architecture, reasoning patterns, and capabilities of autonomous AI agents that can plan, execute, and iterate on complex tasks. Learn the theoretical foundations and practical patterns behind tools like AutoGPT, CrewAI, and LangGraph.', '[{"title":"What Are AI Agents","content":"Define AI agents and distinguish them from simple chatbots and automation scripts through their ability to reason, plan, and act autonomously. Explore the spectrum from simple reflex agents to goal-based and learning agents."},{"title":"Agent Architectures","content":"Study the major agent architecture patterns including ReAct, Plan-and-Execute, and Tree of Thought reasoning. Understand how each architecture trades off between reliability, speed, and capability."},{"title":"Tool Use & Environment Interaction","content":"Examine how agents interact with external tools, APIs, and environments to accomplish real-world tasks. Learn about tool selection, parameter generation, and result interpretation in agent workflows."},{"title":"Memory & Context Management","content":"Understand short-term, long-term, and episodic memory systems that enable agents to maintain context across complex tasks. Study vector databases, conversation buffers, and knowledge graph approaches to agent memory."},{"title":"Evaluation & Safety","content":"Learn frameworks for evaluating agent performance including task completion, efficiency, and error recovery metrics. Study safety considerations including sandboxing, human-in-the-loop controls, and output validation."}]', '["Explain the key architectural patterns behind autonomous AI agents including ReAct, Plan-and-Execute, and Tree of Thought","Analyze how agents use tools, memory systems, and reasoning to accomplish complex multi-step tasks","Evaluate agent systems for performance, reliability, and safety using established frameworks"]', '[{"title":"Agent Architecture Analysis","description":"Study three different AI agent frameworks (AutoGPT, CrewAI, LangGraph) and map each to its underlying architecture pattern. Create a comparison document analyzing their reasoning approaches, tool use, and memory systems.","type":"hands-on"},{"title":"Agent Reasoning Trace","description":"Run an AI agent on a complex task and trace its complete reasoning process including planning, tool selection, execution, error handling, and iteration. Annotate each step with the architectural pattern being used.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn AI agent fundamentals for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 14, 'Building AI Agents', 'Create Your Own Agent', 'Build functional AI agents from scratch using frameworks like LangChain, LangGraph, and the Anthropic SDK with custom tools and reasoning loops. Implement planning, execution, error recovery, and human-in-the-loop workflows for production agent systems.', '[{"title":"Agent Framework Setup","content":"Set up development environments for building agents with LangChain, LangGraph, CrewAI, and the Anthropic tool-use API. Understand the abstractions each framework provides and when to use them."},{"title":"Building the Reasoning Loop","content":"Implement the core agent loop including observation, reasoning, action selection, and result processing. Build ReAct-style agents that alternate between thinking and acting to solve complex tasks."},{"title":"Custom Tool Development","content":"Create custom tools that agents can use to interact with files, databases, APIs, and external services. Implement proper tool descriptions, parameter schemas, and error handling for reliable agent tool use."},{"title":"Multi-Agent Systems","content":"Design and implement multi-agent systems where specialized agents collaborate on complex tasks. Build orchestration patterns including sequential chains, parallel execution, and hierarchical delegation."},{"title":"Production Deployment","content":"Deploy agents with proper logging, monitoring, cost controls, and human-in-the-loop approval workflows. Implement retry logic, timeout handling, and graceful degradation for production reliability."}]', '["Build functional AI agents with custom tools and reasoning loops using modern agent frameworks","Implement multi-agent systems with proper orchestration, communication, and task delegation","Deploy production-ready agent systems with monitoring, cost controls, and human-in-the-loop safety"]', '[{"title":"Custom Agent Builder","description":"Build an AI agent from scratch that can research topics, write code, run tests, and iterate on solutions. Implement at least five custom tools, proper error recovery, and conversation memory. Test on three different complex tasks.","type":"hands-on"},{"title":"Multi-Agent Project","description":"Design and implement a multi-agent system where a planner agent delegates to specialist agents (coder, reviewer, tester) to complete a software development task. Include inter-agent communication and result aggregation.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn to build AI agents for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 15, 'AI and Cloud Services', 'AWS, Azure & GCP', 'Leverage AI coding tools to accelerate cloud service development across AWS, Azure, and Google Cloud Platform. Learn to use AI for infrastructure provisioning, serverless function development, and cloud-native application architecture.', '[{"title":"Cloud SDK & CLI with AI","content":"Use AI to generate cloud CLI commands and SDK code for AWS, Azure, and GCP service management. Master prompting techniques for correct IAM policies, resource configurations, and service integrations."},{"title":"Serverless Development","content":"Build serverless functions and applications using AI-assisted development across Lambda, Azure Functions, and Cloud Functions. Generate event triggers, API gateways, and function configurations with AI tools."},{"title":"Cloud-Native Architecture","content":"Design cloud-native application architectures using AI to evaluate service options and trade-offs across providers. Generate architecture diagrams, cost estimates, and migration plans with AI assistance."},{"title":"AI Services Integration","content":"Integrate cloud AI services including AWS Bedrock, Azure OpenAI, and Google Vertex AI into applications. Use AI coding tools to generate service client code, handle authentication, and manage API quotas."},{"title":"Multi-Cloud & Cost Optimization","content":"Use AI to design multi-cloud strategies and optimize cloud spending through resource right-sizing and reserved capacity. Generate cost monitoring dashboards and automated scaling policies with AI."}]', '["Use AI tools to generate correct cloud infrastructure code and CLI commands across AWS, Azure, and GCP","Build serverless applications with AI-assisted development including event triggers, API gateways, and function orchestration","Design cost-optimized cloud-native architectures using AI for service selection and configuration"]', '[{"title":"Serverless API Deployment","description":"Use AI to build and deploy a complete serverless API on AWS Lambda (or equivalent) with API Gateway, DynamoDB, authentication, and monitoring. Generate all infrastructure-as-code templates and function implementations with AI.","type":"hands-on"},{"title":"Cloud Architecture Design","description":"Given a set of application requirements, use AI to design a cloud-native architecture on two different providers. Compare cost estimates, service capabilities, and operational complexity. Generate Terraform templates for both.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn cloud services with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 16, 'AI Security in Code', 'Vulnerability Detection', 'Use AI tools to detect, analyze, and remediate security vulnerabilities in codebases including injection attacks, authentication flaws, and data exposure risks. Build security-first development workflows with AI-powered scanning and automated fix generation.', '[{"title":"AI-Powered Vulnerability Scanning","content":"Use AI tools to perform static and dynamic security analysis on codebases to detect common vulnerability patterns. Configure AI-powered security scanners like Snyk, Semgrep, and CodeQL with custom rule sets."},{"title":"Injection & Input Validation","content":"Detect and fix SQL injection, XSS, command injection, and other input validation vulnerabilities using AI analysis. Generate secure input sanitization, parameterized queries, and output encoding with AI assistance."},{"title":"Authentication & Authorization Flaws","content":"Use AI to audit authentication implementations for common weaknesses including insecure token handling and privilege escalation. Generate secure authentication flows, session management, and RBAC implementations with AI."},{"title":"Dependency & Supply Chain Security","content":"Leverage AI to analyze dependency trees for known vulnerabilities, license issues, and supply chain risks. Build automated dependency update workflows with AI-powered compatibility and security assessment."},{"title":"Security-First Development Workflow","content":"Integrate AI security tools into your development pipeline with pre-commit hooks, CI scans, and automated fix suggestions. Build a security review checklist and threat modeling process powered by AI analysis."}]', '["Use AI tools to detect and remediate common security vulnerabilities including injection, XSS, and authentication flaws","Build automated security scanning pipelines with AI-powered analysis and fix generation","Implement security-first development workflows integrating AI vulnerability detection at every stage"]', '[{"title":"Vulnerability Hunt","description":"Run AI security analysis on a deliberately vulnerable application (like OWASP Juice Shop). Identify at least 10 vulnerabilities, classify their severity, and use AI to generate remediation code for each. Verify fixes eliminate the vulnerabilities.","type":"hands-on"},{"title":"Security Pipeline Builder","description":"Build a complete security-focused CI/CD pipeline that includes dependency scanning, SAST, secret detection, and AI-powered code review for security issues. Configure automated fix PRs and security reporting dashboards.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn code security with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 17, 'Performance Optimization with AI', 'Profiling & Tuning', 'Apply AI tools to identify performance bottlenecks, optimize critical code paths, and tune application performance across frontend and backend systems. Master AI-assisted profiling, algorithmic optimization, and resource management.', '[{"title":"AI-Assisted Profiling","content":"Use AI to interpret profiling data from CPU, memory, and network profilers to identify genuine performance bottlenecks. Learn to prompt AI with flame graphs, heap snapshots, and trace data for actionable optimization suggestions."},{"title":"Algorithmic Optimization","content":"Leverage AI to analyze algorithm complexity, suggest more efficient alternatives, and optimize data structure choices. Use AI to refactor hot code paths with better time and space complexity while maintaining correctness."},{"title":"Frontend Performance","content":"Apply AI to optimize frontend performance including bundle size reduction, rendering efficiency, and load time improvements. Generate lazy loading strategies, code splitting configurations, and image optimization pipelines with AI."},{"title":"Backend & Database Tuning","content":"Use AI to optimize server response times through connection pooling, query optimization, and caching layer implementation. Generate load testing scripts and analyze results with AI to identify scalability bottlenecks."},{"title":"Continuous Performance Monitoring","content":"Build AI-powered performance monitoring and regression detection systems that alert on degradation. Generate performance budgets, benchmark suites, and automated regression tests using AI tools."}]', '["Use AI tools to interpret profiling data and identify genuine performance bottlenecks in complex applications","Optimize critical code paths with AI-suggested algorithmic improvements and data structure changes","Build continuous performance monitoring systems with AI-powered regression detection and alerting"]', '[{"title":"Performance Audit","description":"Profile a provided application with known performance issues. Use AI to analyze profiling data, identify the top five bottlenecks, implement optimizations for each, and measure the cumulative improvement. Document before and after metrics.","type":"hands-on"},{"title":"Load Testing & Tuning","description":"Generate load testing scripts with AI for a web application. Run increasing load scenarios, use AI to analyze the results and identify breaking points, then implement optimizations to double the application''s throughput capacity.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn performance optimization with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 18, 'AI for Mobile Development', 'Cross-Platform Apps', 'Build cross-platform mobile applications using AI-assisted development with React Native, Flutter, and modern mobile frameworks. Master AI-driven workflows for mobile UI generation, platform-specific optimization, and app store deployment.', '[{"title":"Mobile Project Setup with AI","content":"Use AI to scaffold cross-platform mobile projects with proper configuration for React Native or Flutter development. Generate project structure, navigation setup, and platform-specific configurations with AI assistance."},{"title":"Mobile UI Generation","content":"Build mobile UI components and screens using AI to generate platform-adaptive layouts and native-feeling interactions. Use AI to create responsive designs that work across phones, tablets, and different screen densities."},{"title":"Platform-Specific Features","content":"Implement native device features including camera, GPS, push notifications, and biometric authentication using AI-generated code. Handle platform differences and permission management with AI-assisted cross-platform abstractions."},{"title":"State & Data Management","content":"Build mobile state management and offline-first data architectures using AI-assisted development. Implement local storage, API synchronization, and conflict resolution patterns with AI-generated code."},{"title":"Testing & Deployment","content":"Generate mobile test suites including unit, integration, and end-to-end tests with AI tools. Use AI to configure build pipelines, code signing, and app store submission workflows."}]', '["Build cross-platform mobile applications using AI-assisted development with React Native or Flutter","Implement native device features and platform-specific optimizations using AI-generated code","Configure mobile testing, build pipelines, and app store deployment workflows with AI assistance"]', '[{"title":"Mobile App Builder","description":"Build a complete cross-platform mobile app with at least five screens, navigation, native device features (camera or GPS), and offline data storage using AI assistance. Test on both iOS and Android simulators.","type":"hands-on"},{"title":"Native Feature Integration","description":"Take an existing mobile app and use AI to add three native features: push notifications, biometric authentication, and deep linking. Handle all platform-specific configurations and permission flows.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn mobile development with AI assistance for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 40);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 19, 'Open Source AI Tools', 'Community Resources', 'Explore the rich ecosystem of open source AI coding tools including local models, code assistants, and development frameworks. Learn to evaluate, deploy, and contribute to open source AI projects for software development.', '[{"title":"Open Source AI Landscape","content":"Survey the current ecosystem of open source AI coding tools including Ollama, LM Studio, Continue, Tabby, and CodeLlama. Understand licensing models, community health indicators, and how to evaluate tool maturity."},{"title":"Local Model Deployment","content":"Set up and run local AI models for code completion and chat using Ollama, llama.cpp, and similar tools. Configure hardware requirements, quantization options, and model selection for optimal local performance."},{"title":"Open Source Code Assistants","content":"Install and configure open source code assistant alternatives including Continue, Tabby, and Cody for local-first AI development. Compare capabilities, latency, and quality against commercial alternatives."},{"title":"AI Development Frameworks","content":"Explore open source AI frameworks including LangChain, LlamaIndex, Haystack, and Semantic Kernel for building AI applications. Understand the strengths, community support, and production readiness of each framework."},{"title":"Contributing to AI Open Source","content":"Learn how to evaluate, use, and contribute to open source AI projects including model fine-tuning and tool development. Build custom extensions, plugins, and integrations for open source AI coding tools."}]', '["Evaluate and deploy open source AI coding tools for local-first development without cloud dependencies","Configure local language models for code completion and chat with optimized performance settings","Navigate the open source AI ecosystem to select appropriate frameworks and tools for specific project needs"]', '[{"title":"Local AI Setup","description":"Set up a complete local AI development environment using open source tools only. Install a local model with Ollama, configure an open source code assistant, and complete a coding task entirely with local AI. Benchmark against cloud-based alternatives.","type":"hands-on"},{"title":"Framework Comparison","description":"Build the same RAG chatbot application using three different open source frameworks (LangChain, LlamaIndex, and one other). Compare developer experience, performance, documentation quality, and output accuracy for each.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student learn open source AI tools for software development. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 35);
INSERT INTO classes (level, sort_order, title, subtitle, description, content_outline, objectives, exercises, agent_zero_prompt, duration_minutes) VALUES ('advanced', 20, 'Capstone: Full AI Project', 'Build a Complete Application', 'Apply everything you''ve learned to build a complete, production-ready application using AI-assisted development from conception through deployment. Demonstrate mastery of AI coding tools across the full software development lifecycle.', '[{"title":"Project Planning & Architecture","content":"Use AI to define project requirements, design system architecture, and create a development roadmap for your capstone application. Generate technical specifications, database schemas, and API contracts from your project vision."},{"title":"Core Feature Development","content":"Build the core features of your application using AI-assisted development for both frontend and backend components. Apply code completion, generation, and refactoring techniques learned throughout the course."},{"title":"Testing & Quality Assurance","content":"Generate comprehensive test suites covering unit, integration, and end-to-end testing for your capstone project. Use AI for code review, security scanning, and performance profiling to ensure production quality."},{"title":"DevOps & Deployment","content":"Set up CI/CD pipelines, container configurations, and cloud deployment using AI-generated infrastructure code. Implement monitoring, logging, and alerting for your production application."},{"title":"Presentation & Retrospective","content":"Document your AI-assisted development process including time saved, quality improvements, and lessons learned. Present your application and reflect on which AI tools and techniques provided the most value."}]', '["Build a complete, production-ready application using AI-assisted development across the full software lifecycle","Demonstrate proficiency with AI tools for planning, coding, testing, security, and deployment","Evaluate and articulate the impact of AI-assisted development on productivity, code quality, and learning"]', '[{"title":"Capstone Application","description":"Build and deploy a complete application of your choice using AI assistance at every stage. Must include user authentication, database persistence, API layer, responsive frontend, test coverage above 80%, CI/CD pipeline, and production deployment.","type":"hands-on"},{"title":"Development Retrospective","description":"Write a detailed retrospective documenting your AI-assisted development process. Include metrics on time saved, tools used at each phase, AI accuracy rates, and a ranked list of the most valuable AI techniques you discovered throughout the course.","type":"hands-on"}]', 'You are an AI tutor helping an advanced student complete their capstone project for an AI-assisted software development course. Provide code examples, technical depth, and best practices. Assume the student has programming experience and wants practical, implementation-focused guidance.', 45);
